function getBareme(cp,fnName,anciennete){
  const bar=BAREMES[cp];if(!bar)return null;
  const classe=bar.fnClassMap?.[fnName];if(!classe)return null;
  if(bar.type==='monthly'){
    const years=Object.keys(bar.grid).map(Number).sort((a,b)=>a-b);
    let yr=years[0];for(const y of years){if(anciennete>=y)yr=y;else break;}
    const monthly=bar.grid[yr]?.[classe];if(!monthly)return null;
    return{monthly,hourly:+(monthly/164.6666).toFixed(4),classe,classLabel:bar.classes[classe],ancYr:yr,cp,type:"monthly",indexDate:bar.indexDate,indexPct:bar.indexPct,regime:bar.regime};
  }
  if(bar.type==='hourly'){
    let hourly;
    if(typeof Object.values(bar.grid)[0]==='object'){
      const years=Object.keys(bar.grid).map(Number).sort((a,b)=>a-b);
      let yr=years[0];for(const y of years){if(anciennete>=y)yr=y;else break;}
      hourly=bar.grid[yr]?.[classe];
    } else { hourly=bar.grid[classe]; }
    if(!hourly)return null;
    const factor=bar.monthlyFactor||((bar.weeklyH||38)*52/12);
    return{monthly:+(hourly*factor).toFixed(2),hourly,classe,classLabel:bar.classes[classe],ancYr:anciennete,cp,type:"hourly",indexDate:bar.indexDate,indexPct:bar.indexPct,regime:bar.regime};
  }
  return null;
}

function getCPAvantages(cp){
  const bar=BAREMES[cp];if(!bar)return[];const avs=[];
  if(bar.primeAnnuelle)avs.push({l:"Prime annuelle (juin)",v:fmt(bar.primeAnnuelle)});
  if(bar.primeFinAnnee)avs.push({l:"Prime fin d\'annГ©e",v:bar.primeFinAnnee});
  if(bar.ecoChequesMax)avs.push({l:"Гүco-chГЁques (max/an)",v:fmt(bar.ecoChequesMax)});
  if(bar.transport?.velo)avs.push({l:"IndemnitГ© vГ©lo",v:`${bar.transport.velo} вӮ¬/km (max ${bar.transport.maxVeloJour}вӮ¬/jour)`});
  if(bar.timbreFidelite)avs.push({l:"Timbres fidГ©litГ©",v:`${(bar.timbreFidelite*100)}% sal. annuel`});
  if(bar.timbreIntemperie)avs.push({l:"Timbres intempГ©ries",v:`${(bar.timbreIntemperie*100)}% sal. annuel`});
  if(bar.mobilite)avs.push({l:"IndemnitГ© mobilitГ©",v:`${bar.mobilite.parKm} вӮ¬/km (max ${bar.mobilite.maxKm}km)`});
  if(bar.reposComp)avs.push({l:"Jours repos compensatoires",v:`${bar.reposComp} jours/an`});
  if(bar.primeNuit)avs.push({l:"Prime nuit",v:`+${(bar.primeNuit*100)}%`});
  if(bar.primeWeekendSam)avs.push({l:"Prime samedi",v:`+${(bar.primeWeekendSam*100)}%`});
  if(bar.primeWeekendDim)avs.push({l:"Prime dimanche",v:`+${(bar.primeWeekendDim*100)}%`});
  if(bar.primeAttractivite)avs.push({l:"Prime attractivitГ©",v:`${(bar.primeAttractivite*100)}%`});
  if(bar.indemniteNuit)avs.push({l:"IndemnitГ© nuit (0h-5h)",v:`${bar.indemniteNuit} вӮ¬/h`});
  if(bar.indemniteVetements)avs.push({l:"IndemnitГ© vГӘtements",v:`${bar.indemniteVetements} вӮ¬/jour`});
  return avs;
}

// в”Җв”Җв”Җ PAYROLL CALCULATION ENGINE (Formule-clГ© SPF Finances) в”Җв”Җв”Җ
function calc(emp, per, co) {
  const r = {};
  const hr = (emp.monthlySalary||0) / (LEGAL.WD * LEGAL.WHD);
  r.base = emp.monthlySalary || 0;
  r.overtime = (per.overtimeH||0) * hr * 1.5;
  r.sunday = (per.sundayH||0) * hr * 2;
  r.night = (per.nightH||0) * hr * 1.25;
  r.bonus = per.bonus || 0;
  r.y13 = per.y13 || 0;
  r.sickPay = (per.sickG||0) * (r.base / LEGAL.WD);
  r.gross = r.base + r.overtime + r.sunday + r.night + r.bonus + r.y13 + r.sickPay;

  // в”Җв”Җ HEURES SUP VOLONTAIRES BRUT=NET (Nouveau rГ©gime 01/04/2026 + Relance T1) в”Җв”Җ
  // 360h/an (450h horeca), dont 240h (360h horeca) exonГ©rГ©es ONSS+PP = brut=net
  // Pas de sursalaire, pas de repos compensatoire. Accord Г©crit 1 an.
  // Heures relance (T1/2026 transitoire): 120h brut=net, dГ©duites du quota 240h
  r.hsVolontBrutNet = (per.hsVolontBrutNet||0) * hr; // montant brut=net (pas de sursalaire)
  r.hsRelance = (per.hsRelance||0) * hr;
  r.hsBrutNetTotal = r.hsVolontBrutNet + r.hsRelance; // total brut=net (non soumis ONSS/PP)

  // в”Җв”Җ MI-TEMPS MГүDICAL / REPRISE PROGRESSIVE (Art. 100В§2 Loi coord. 14/07/1994) в”Җв”Җ
  // Le travailleur reconnu en incapacitГ© par le mГ©decin-conseil de la mutuelle
  // reprend le travail Г  temps partiel avec l'accord du mГ©decin du travail.
  //
  // MГ©canisme:
  //   1. L'employeur paie le salaire PROPORTIONNEL aux heures prestГ©es
  //   2. L'INAMI (mutuelle) verse un COMPLГүMENT d'indemnitГ©s au travailleur
  //   3. Le complГ©ment INAMI = 60% du brut normal Г— (heures non prestГ©es / heures normales)
  //      mais plafonnГ© et avec rГЁgle de cumul (max 20% de perte par rapport Г  avant l'incapacitГ©)
  //
  // Impact sur la fiche de paie:
  //   - Brut = prorata des heures prestГ©es (pas le brut normal!)
  //   - ONSS = calculГ© sur le brut prorata (pas sur le brut normal)
  //   - PP = calculГ© sur le brut prorata (barГЁme temps partiel)
  //   - L'indemnitГ© INAMI est hors fiche de paie (versГ©e directement par la mutuelle)
  //   - Mention "pour mГ©moire" du complГ©ment INAMI sur la fiche
  //
  // Formulaires:
  //   - C3.2: dГ©claration de reprise au mГ©decin-conseil
  //   - E10: Г©valuation mГ©decin du travail (formulaire de rГ©intГ©gration)
  //   - DRS (eBox): dГ©claration reprise du travail Г  la mutuelle
  //
  // DurГ©e: illimitГ©e (aussi longtemps que le mГ©decin-conseil autorise)
  // ONSS: sur brut prorata uniquement
  // PP: barГЁme proportionnel temps partiel (fraction d'occupation)
  r.miTempsMed = per.miTempsMed || false;
  r.miTempsHeures = per.miTempsHeures || 0;
  r.miTempsFraction = 1; // fraction d'occupation
  r.miTempsINAMI = per.miTempsINAMI || 0;
  r.miTempsBrutOriginal = r.base; // brut avant prorata

  if (r.miTempsMed && r.miTempsHeures > 0 && (emp.whWeek || 38) > 0) {
    r.miTempsFraction = r.miTempsHeures / (emp.whWeek || 38);
    // Recalculer le brut au prorata des heures prestГ©es
    r.base = Math.round((emp.monthlySalary || 0) * r.miTempsFraction * 100) / 100;
    // Recalculer les composantes proportionnelles
    r.sickPay = (per.sickG || 0) * (r.base / LEGAL.WD);
    r.gross = r.base + r.overtime + r.sunday + r.night + r.bonus + r.y13 + r.sickPay;
    // Estimation du complГ©ment INAMI si pas renseignГ©
    // RГЁgle: 60% du brut limitГ© (plafonnГ© Г  вүҲ 106,16вӮ¬/j en 2026) Г— fraction non prestГ©e
    if (r.miTempsINAMI === 0) {
      const brutJourNormal = (emp.monthlySalary || 0) / LEGAL.WD;
      const plafondINAMI = 106.16; // plafond journalier INAMI 2026 (adaptГ©)
      const brutJourPlafonnГ© = Math.min(brutJourNormal, plafondINAMI);
      const tauxINAMI = 0.60; // 60% (cohabitant) вҖ” peut ГӘtre 65% (chef de famille) ou 55% (isolГ©)
      r.miTempsINAMI = Math.round(brutJourPlafonnГ© * tauxINAMI * LEGAL.WD * (1 - r.miTempsFraction) * 100) / 100;
    }
  }

  // в”Җв”Җ ATN Voiture de sociГ©tГ© (Art. 36 CIR 92) в”Җв”Җ
  r.atnCar = 0; r.atnPct = 0; r.cotCO2 = 0;
  const carFuel = emp.carFuel || 'none';
  const carCO2 = parseInt(emp.carCO2) || 0;
  const carCatVal = parseFloat(emp.carCatVal) || 0;
  if (carFuel !== 'none' && carCatVal > 0) {
    if (carFuel === 'electrique') {
      r.atnPct = 4;
      r.atnCar = Math.max(1600/12, (carCatVal * (6/7) * 0.04) / 12);
      r.cotCO2 = 31.34; // minimum
    } else {
      const refCO2 = (carFuel === 'diesel') ? 84 : 102;
      const delta = carCO2 - refCO2;
      r.atnPct = Math.max(4, Math.min(18, 5.5 + (delta * 0.1)));
      r.atnCar = Math.max(1600/12, (carCatVal * (6/7) * (r.atnPct/100)) / 12);
      // Cotisation CO2 patronale (solidaritГ© ONSS)
      if (carFuel === 'diesel') r.cotCO2 = Math.max(31.34, (carCO2 * 0.00714 * 71.4644) + 31.34);
      else r.cotCO2 = Math.max(31.34, (carCO2 * 0.00714 * 83.6644) + 31.34);
    }
  }

  // в”Җв”Җ ATN Autres avantages en nature (AR 18/12/2024 вҖ” Forfaits 2026) в”Җв”Җ
  r.atnGSM = emp.atnGSM ? 3.00 : 0;         // 36вӮ¬/an = 3вӮ¬/mois
  r.atnPC = emp.atnPC ? 6.00 : 0;            // 72вӮ¬/an = 6вӮ¬/mois
  r.atnInternet = emp.atnInternet ? 5.00 : 0; // 60вӮ¬/an = 5вӮ¬/mois
  r.atnChauffage = emp.atnChauffage ? 177.50 : 0; // 2.130вӮ¬/an = 177,50вӮ¬/mois
  r.atnElec = emp.atnElec ? 88.33 : 0;       // 1.060вӮ¬/an = 88,33вӮ¬/mois
  // ATN Logement gratuit (Art. 18 AR/CIR92 вҖ” Forfaits 2026)
  // Non-dirigeant: forfait fixe = RC indexГ© Г— 100/60
  // Dirigeant (statut=dirigeant): RC indexГ© Г— 100/60 Г— 3,80 (coeff. dirigeant)
  // Coefficient indexation RC 2026: 2,1763 (exercice d'imposition 2027)
  // Si meublГ©: + 5/3 du montant
  r.atnLogement = 0;
  if (emp.atnLogement && parseFloat(emp.atnLogementRC) > 0) {
    const rc = parseFloat(emp.atnLogementRC);
    const rcIndex = rc * 2.1763; // RC indexГ© 2026
    const isDirigeant = (emp.statut === 'dirigeant');
    if (isDirigeant) {
      // Dirigeant: RC indexГ© Г— 100/60 Г— coeff. 3,80 (si RC > 745вӮ¬) ou Г— 1,25 (si RC вүӨ 745вӮ¬)
      r.atnLogement = rc <= 745
        ? (rcIndex * 100 / 60 * 1.25) / 12
        : (rcIndex * 100 / 60 * 3.80) / 12;
    } else {
      // Non-dirigeant: forfait fixe par RC non indexГ©
      r.atnLogement = (rcIndex * 100 / 60) / 12;
    }
  }
  r.atnAutresTot = r.atnGSM + r.atnPC + r.atnInternet + r.atnChauffage + r.atnElec + r.atnLogement;
  r.atnTotal = r.atnCar + r.atnAutresTot;

  // в”Җв”Җ VГүLO DE SOCIГүTГү (Loi 25/11/2021 + Art. 38В§1er 14В°a CIR 92) в”Җв”Җ
  // Depuis 01/01/2024: l'ATN vГ©lo de sociГ©tГ© = 0вӮ¬ (exonГ©rГ© IPP et ONSS)
  // Conditions: usage effectif pour dГ©placements domicile-travail (mГӘme partiel)
  // L'employeur supporte le coГ»t du leasing (dГ©ductible 100%)
  // Types: vГ©lo classique, vГ©lo Г©lectrique (вүӨ25km/h), speed pedelec (вүӨ45km/h)
  // CUMULABLE avec l'indemnitГ© vГ©lo 0,27вӮ¬/km (pour les km effectivement parcourus)
  // Le speed pedelec est fiscalement assimilГ© Г  un vГ©lo (pas une moto)
  r.veloSociete = emp.veloSociete || false;
  r.veloType = emp.veloType || 'none';
  r.atnVelo = 0; // ATN = 0вӮ¬ depuis 01/01/2024 (exonГ©rГ©)
  r.veloLeasingMois = emp.veloLeasingMois || 0; // coГ»t employeur
  r.veloValeur = emp.veloValeur || 0;

  // IndemnitГ© vГ©lo cumulable: 0,27вӮ¬/km A/R mГӘme avec vГ©lo de sociГ©tГ©
  // вҶ’ dГ©jГ  calculГ©e dans r.transport si commType === 'bike'

  // в”Җв”Җ CARTE CARBURANT / RECHARGE (Art. 36В§2 CIR 92) в”Җв”Җ
  // La carte carburant liГ©e Г  une voiture de sociГ©tГ© est incluse dans l'ATN voiture
  // (pas d'ATN sГ©parГ©) SAUF si la carte permet un usage privГ© illimitГ©:
  //   вҶ’ L'ATN voiture couvre dГ©jГ  les frais de carburant
  //   вҶ’ Si carte carburant SANS voiture de sociГ©tГ© = avantage imposable Г  100%
  r.carteCarburant = emp.carteCarburant || false;
  r.carteCarburantMois = emp.carteCarburantMois || 0;
  // Si pas de voiture de sociГ©tГ© mais carte carburant вҶ’ ATN = montant total
  r.atnCarteCarburant = (r.carteCarburant && !r.atnCar) ? r.carteCarburantMois : 0;
  // Si voiture de sociГ©tГ© + carte carburant вҶ’ inclus dans ATN voiture (pas d'ATN supplГ©mentaire)

  // в”Җв”Җ BORNE DE RECHARGE DOMICILE (Art. 14536 CIR 92 + Loi 25/11/2021) в”Җв”Җ
  // L'employeur peut installer une borne de recharge au domicile du travailleur
  // Pas d'ATN pour le travailleur si la borne sert Г  recharger la voiture de sociГ©tГ©
  // L'employeur dГ©duit le coГ»t Г  100% (si borne intelligente bidirectionnelle)
  // L'Г©lectricitГ© de recharge pour usage privГ©: ATN = coГ»t rГ©el ou forfait
  r.borneRecharge = emp.borneRecharge || false;
  r.borneRechargeCoГ»t = emp.borneRechargeCoГ»t || 0;
  // ATN borne: 0вӮ¬ si voiture de sociГ©tГ© (fait partie du package)
  // ATN borne: coГ»t rГ©el si pas de voiture de sociГ©tГ©
  r.atnBorne = (r.borneRecharge && !r.atnCar) ? r.borneRechargeCoГ»t : 0;

  // Ajouter aux ATN autres si applicable
  r.atnAutresTot += r.atnCarteCarburant + r.atnBorne;
  r.atnTotal = r.atnCar + r.atnAutresTot;

  // в”Җв”Җ ONSS Travailleur в”Җв”Җ
  const isOuvrier = (emp.statut === 'ouvrier');
  const onssBase = isOuvrier ? r.gross * LEGAL.ONSS_DETAIL_2026.majoration_ouvrier : r.gross;
  r.onssW = onssBase * LEGAL.ONSS_W;
  // в”Җв”Җ Bonus Г  l'emploi 2026 вҖ” Volet A (bas salaires) + Volet B (trГЁs bas salaires) в”Җв”Җ
  // Source: Instructions ONSS T1/2026 + Partena Professional
  const BE = LEGAL.BONUS_2026;
  r.empBonusA = 0; r.empBonusB = 0;
  if (isOuvrier) {
    // Ouvrier (dГ©clarГ© Г  108%)
    if (r.gross * 1.08 <= BE.O_A_S2) r.empBonusA = BE.O_A_MAX;
    else if (r.gross * 1.08 <= BE.O_A_S1) r.empBonusA = Math.max(0, BE.O_A_MAX - BE.O_A_COEFF * (r.gross * 1.08 - BE.O_A_S2));
    if (r.gross * 1.08 <= BE.O_B_S2) r.empBonusB = BE.O_B_MAX;
    else if (r.gross * 1.08 <= BE.O_B_S1) r.empBonusB = Math.max(0, BE.O_B_MAX - BE.O_B_COEFF * (r.gross * 1.08 - BE.O_B_S2));
  } else {
    // EmployГ© (dГ©clarГ© Г  100%)
    if (r.gross <= BE.A_S2) r.empBonusA = BE.A_MAX;
    else if (r.gross <= BE.A_S1) r.empBonusA = Math.max(0, BE.A_MAX - BE.A_COEFF * (r.gross - BE.A_S2));
    if (r.gross <= BE.B_S2) r.empBonusB = BE.B_MAX;
    else if (r.gross <= BE.B_S1) r.empBonusB = Math.max(0, BE.B_MAX - BE.B_COEFF * (r.gross - BE.B_S2));
  }
  r.empBonus = Math.min(r.empBonusA + r.empBonusB, r.onssW); // ne peut dГ©passer cotisation perso
  r.onssNet = r.onssW - r.empBonus;

  // в”Җв”Җ ONSS Employeur в”Җв”Җ
  const sectInfo = LEGAL.ONSS_SECTEUR[emp.cp] || LEGAL.ONSS_SECTEUR['default'];
  r.onssE_rate = sectInfo.e;
  r.onssE = onssBase * sectInfo.e;
  r.onssE_note = sectInfo.note;
  r.onssE_type = sectInfo.type || 'marchand';
  // Cotisations spГ©ciales patronales
  r.onss_ffe = onssBase * (emp.staffCount >= 20 ? LEGAL.ONSS_DETAIL_2026.ffe_grand : LEGAL.ONSS_DETAIL_2026.ffe_petit);
  r.onss_chomTemp = onssBase * LEGAL.ONSS_DETAIL_2026.chomage_temp;
  r.onss_amiante = onssBase * LEGAL.ONSS_DETAIL_2026.amiante;

  // в”Җв”Җ RГ©duction structurelle ONSS T1/2026 в”Җв”Җ
  // Formule: Ps = R Г— Вө Г— (J/D) вҖ” R = F + Оұ(S0-S) + Оі(S2-S) + Оҙ(W-S1)
  // S = salaire trimestriel de rГ©fГ©rence, W = salaire trimestriel rГ©el
  // Source: ONSS Instructions administratives + Easypay Group 09/01/2026
  const RS = LEGAL.RED_STRUCT_2026;
  const salTrim = r.gross * 3; // salaire trimestriel
  const salRef = salTrim; // temps plein = salaire rГ©el (proratisГ© si TP partiel)
  // Fraction de prestation (Вө) вҖ” Art. 353bis/5 Loi-programme 24/12/2002
  // Temps partiel: fraction = heures prestГ©es / heures temps plein
  const fractionPrest = emp.regime === 'full' ? 1 : (emp.whWeek || 38) / 38;
  r.redStructCat = r.onssE_type === 'non-marchand' ? 2 :
    (emp.statut === 'eta' ? 3 : (emp.statut === 'eta_handi' ? 4 : 1));
  // cat 1=marchand, 2=non-marchand, 3=ETA, 4=ETA handicapГ©
  let redR = 0;
  if (r.redStructCat === 1) {
    // CatГ©gorie 1: secteur marchand privГ©
    const compBas = salRef < RS.CAT1_S0 ? RS.CAT1_alpha * (RS.CAT1_S0 - salRef) : 0;
    const compTBas = salRef < RS.CAT1_S2 ? RS.CAT1_gamma * (RS.CAT1_S2 - salRef) : 0;
    redR = RS.CAT1_F + compBas + compTBas;
  } else if (r.redStructCat === 2) {
    // CatГ©gorie 2: Maribel social / non-marchand
    const compBas = salRef < RS.CAT2_S0 ? RS.CAT2_alpha * (RS.CAT2_S0 - salRef) : 0;
    const compTBas = salRef < RS.CAT2_S2 ? RS.CAT2_gamma * (RS.CAT2_S2 - salRef) : 0;
    const compHaut = salRef > RS.CAT2_S1 ? RS.CAT2_delta * (salRef - RS.CAT2_S1) : 0;
    redR = RS.CAT2_F + compBas + compTBas + compHaut;
  } else if (r.redStructCat === 3) {
    // CatГ©gorie 3: Entreprises de travail adaptГ© (ETA)
    const compBas = salRef < RS.CAT3_S0 ? RS.CAT3_alpha * (RS.CAT3_S0 - salRef) : 0;
    const compTBas = salRef < RS.CAT3_S2 ? RS.CAT3_gamma * (RS.CAT3_S2 - salRef) : 0;
    redR = RS.CAT3_F + compBas + compTBas;
  } else if (r.redStructCat === 4) {
    // CatГ©gorie 3bis: ETA travailleurs moins valides
    const compBas = salRef < RS.CAT3B_S0 ? RS.CAT3B_alpha * (RS.CAT3B_S0 - salRef) : 0;
    const compTBas = salRef < RS.CAT3B_gamma ? RS.CAT3B_gamma * (RS.CAT3B_S2 - salRef) : 0;
    redR = RS.CAT3B_F + compBas + compTBas;
  }
  // Appliquer la fraction de prestation (temps partiel)
  redR = Math.max(0, redR * fractionPrest);
  // Plancher: la rГ©duction ne peut pas ГӘtre nГ©gative
  // Plafond: la rГ©duction ne peut pas excГ©der les cotisations patronales dues
  r.redStruct = Math.min(redR, r.onssE * 3); // montant trimestriel de rГ©duction (plafonnГ©)
  r.redStructMois = Math.round(r.redStruct / 3 * 100) / 100; // mensualisГ©
  r.redStructFraction = fractionPrest;
  // Appliquer rГ©duction sur cotisation patronale effective
  r.onssE = Math.max(0, r.onssE - r.redStructMois);

  // ATN ajoutГ© au revenu imposable (pas Г  l'ONSS, pas au brut payГ©)
  r.taxGross = r.gross - r.onssNet + r.atnCar + r.atnAutresTot;

  // в”Җв”Җ TRAVAILLEUR FRONTALIER / TRANSFRONTALIER в”Җв”Җ
  // RГЁglement (CE) 883/2004 + Conventions bilatГ©rales CPDI
  //
  // PRINCIPE ONSS (Art. 11-16 RГЁgl. 883/2004):
  //   вҶ’ Lieu de TRAVAIL dГ©termine le pays ONSS (lex loci laboris)
  //   вҶ’ Travaille en Belgique = ONSS belge, mГӘme si rГ©side en FR/NL/DE/LU
  //   вҶ’ Exception: tГ©lГ©travail frontalier > 25% вҶ’ accord cadre multi-Гүtat
  //
  // PRINCIPE PP / IMPГ”T (Conventions prГ©ventives double imposition):
  //
  // 1. BELGIQUE вҶ” FRANCE (Convention 10/03/1964 + Avenants):
  //   - Ancien rГ©gime frontalier (abrogГ© 01/01/2012): le frontalier FR travaillant
  //     en BE payait l'impГҙt en France вҶ’ exonГ©ration PP en Belgique
  //   - RГүGIME ACTUEL: PP retenu en Belgique (pays de travail)
  //     Le travailleur FR dГ©clare en France mais obtient un crГ©dit d'impГҙt
  //     pour l'impГҙt belge payГ© (Art. 15 + Art. 19 Convention)
  //   - Formulaire 276 Front.: attestation de rГ©sidence fiscale franГ§aise
  //
  // 2. BELGIQUE вҶ” PAYS-BAS (Convention 05/06/2001):
  //   - PP retenu en Belgique. Le travailleur NL dГ©clare aux Pays-Bas
  //     avec crГ©dit d'impГҙt belge (mГ©thode exemption avec progression)
  //   - Depuis 2003: plus de rГ©gime frontalier spГ©cial
  //   - Le NL rГ©sident peut opter pour "kwalificerend buitenlands belastingplichtige"
  //
  // 3. BELGIQUE вҶ” ALLEMAGNE (Convention 11/04/1967 + Protocole 2002):
  //   - PP retenu en Belgique. CrГ©dit d'impГҙt en Allemagne.
  //   - Pas de rГ©gime frontalier spГ©cial
  //
  // 4. BELGIQUE вҶ” LUXEMBOURG (Convention 17/09/1970):
  //   - PP retenu en Belgique pour travail prestГ© en Belgique
  //   - ParticularitГ©: rГЁgle des 24 jours de tolГ©rance (accord amiable 2015)
  //     вҶ’ max 24j/an de tГ©lГ©travail depuis le Luxembourg sans changer l'imposition
  //
  // IMPACT SUR LE CALCUL:
  //   - ONSS: toujours belge si le travail est prestГ© en Belgique
  //   - PP: normalement retenu en Belgique (pas d'exonГ©ration)
  //   - Exception rare: exonГ©ration PP si formulaire 276 Front. + ancien rГ©gime FR
  //   - Formulaire A1: obligatoire pour les dГ©tachements > 1 pays
  //   - Limosa: dГ©claration obligatoire pour travailleurs dГ©tachГ©s VERS la Belgique
  //
  r.frontalier = emp.frontalier || false;
  r.frontalierPays = emp.frontalierPays || '';
  r.frontalierExoPP = emp.frontalierExoPP || false;

  if (r.frontalier) {
    // ONSS: toujours belge (lex loci laboris) вҖ” pas de changement
    // PP: normalement retenu en Belgique
    // Si exonГ©ration PP (ancien rГ©gime FR prГ©-2012 вҖ” cas rГ©siduel trГЁs rare):
    if (r.frontalierExoPP) {
      r.frontalierPPExo = r.tax; // montant PP qui serait retenu
      // r.tax reste calculГ© normalement pour info mais n'est pas retenu
      // вҶ’ c'est au travailleur de dГ©clarer dans son pays de rГ©sidence
    }
    // Le travailleur frontalier a droit aux mГӘmes avantages sociaux belges
    // (chГЁques-repas, transport, etc.) puisqu'il travaille en Belgique
  }

  // в”Җв”Җ TRAVAILLEUR PENSIONNГү вҖ” CUMUL PENSION / TRAVAIL в”Җв”Җ
  // RГ©forme majeure: depuis 01/01/2015, cumul ILLIMITГү pour:
  //   - Pension lГ©gale de retraite (pas anticipГ©e) Г  l'Гўge lГ©gal (66 ans en 2026, 67 en 2030)
  //   - Pension anticipГ©e aprГЁs 45 ans de carriГЁre
  //   - Pension de survie si le bГ©nГ©ficiaire a вүҘ 65 ans
  //
  // Plafonds de cumul (si cumul LIMITГү вҖ” AR 20/12/2006 + index):
  //   - Pension anticipГ©e < 65 ans (salariГ©):
  //     Sans enfant Г  charge: 10.613вӮ¬/an brut (2026)
  //     Avec enfant Г  charge: 13.266вӮ¬/an brut (2026)
  //   - Pension de survie < 65 ans:
  //     Sans enfant Г  charge: 22.509вӮ¬/an brut (2026)
  //     Avec enfant Г  charge: 28.136вӮ¬/an brut (2026)
  //   вҶ’ En cas de dГ©passement: pension rГ©duite du % de dГ©passement (Art. 64 AR 21/12/1967)
  //
  // IMPACT ONSS:
  //   - Cotisation patronale: normale (pas de rГ©duction spГ©ciale)
  //   - Cotisation travailleur: cotisation de solidaritГ© 0% (pas d'ONSS perso)
  //     si pension + revenu > plafond вҶ’ retenue normale 13,07%
  //   вҶ’ EN PRATIQUE: ONSS normal 13,07% s'applique (la solidaritГ© est passГ©e)
  //   вҶ’ Le pensionnГ© n'est PLUS exonГ©rГ© d'ONSS travailleur depuis 2024
  //
  // IMPACT PP:
  //   - BarГЁme normal appliquГ© (mГӘme formule-clГ©)
  //   - MAIS: quotitГ© exemptГ©e peut ГӘtre diffГ©rente si le pensionnГ©
  //     cumule pension + revenu вҶ’ art. 154bis CIR
  //   - La pension elle-mГӘme est imposГ©e sГ©parГ©ment par le SFP (prГ©compte pension)
  //
  // FLEXI-JOB PENSIONNГү:
  //   - Plafond 12.000вӮ¬/an NE s'applique PAS aux pensionnГ©s вҶ’ cumul illimitГ©
  //   - C'est le principal avantage du statut pensionnГ© pour les flexi-jobs
  //
  // COTISATION SPГүCIALE 1,5% (solidaritГ© pensionnГ©):
  //   - Si le pensionnГ© gagne > plafond, cotisation spГ©ciale de solidaritГ©
  //   - Retenue par l'employeur et versГ©e Г  l'ONSS
  //   - Art. 68 Loi 30/03/1994
  //
  // SIGEDIS / SFP: l'employeur dГ©clare les revenus via DmfA.
  //   Le SFP (Service fГ©dГ©ral des Pensions) vГ©rifie le cumul automatiquement.

  r.pensionnГ© = emp.pensionnГ© || false;
  r.pensionType = emp.pensionType || 'none';
  r.pensionCumulIllimite = emp.pensionCumulIllimite || false;
  r.pensionPlafond = 0;
  r.pensionDepassement = false;

  if (r.pensionnГ©) {
    const age = emp.pensionAge || 0;
    const carriere = emp.pensionCarriere || 0;
    const depEnfants = emp.depChildren > 0;

    // DГ©terminer si cumul illimitГ©
    if (r.pensionType === 'legal' && age >= 66) {
      r.pensionCumulIllimite = true; // ГӮge lГ©gal atteint (66 en 2026)
    }
    if (r.pensionType === 'anticipee' && carriere >= 45) {
      r.pensionCumulIllimite = true; // 45 ans de carriГЁre
    }
    if (r.pensionType === 'survie' && age >= 65) {
      r.pensionCumulIllimite = true;
    }

    if (!r.pensionCumulIllimite) {
      // Plafonds de cumul annuels (indexГ©s 2026)
      if (r.pensionType === 'anticipee') {
        r.pensionPlafond = depEnfants ? 13266 : 10613;
      } else if (r.pensionType === 'survie') {
        r.pensionPlafond = depEnfants ? 28136 : 22509;
      }
      // VГ©rifier si dГ©passement estimГ©
      const revenuAnnuelEstime = r.gross * 12;
      if (r.pensionPlafond > 0 && revenuAnnuelEstime > r.pensionPlafond) {
        r.pensionDepassement = true;
        r.pensionDepassPct = Math.round((revenuAnnuelEstime - r.pensionPlafond) / r.pensionPlafond * 100);
      }
    }

    // Cotisation spГ©ciale solidaritГ© pensionnГ© (Art. 68 Loi 30/03/1994)
    // Si le total pension + revenus activitГ© > seuil вҶ’ retenue 0% Г  2%
    // En pratique: dГ©jГ  incluse dans les cotisations ONSS standard
    // Le SFP vГ©rifie a posteriori via DmfA/SIGEDIS

    // ONSS: normal (13,07% trav + taux patronal sectoriel)
    // Pas de changement dans le calcul вҖ” tout est standard
  }

  // в”Җв”Җ PRГүCOMPTE PROFESSIONNEL 2026 вҖ” FORMULE-CLГү COMPLГҲTE SPF FINANCES в”Җв”Җ
  // Annexe III AR/CIR 92 вҖ” Moniteur belge вҖ” Tranches annuelles
  const PP = LEGAL.PP2026;
  const annualGross = r.taxGross * 12;

  // Гүtape 1: Frais professionnels forfaitaires (30%, max 5 930 вӮ¬)
  const isSalarie = (emp.regime !== 'dirigeant');
  const fpPct = isSalarie ? PP.FP_PCT : PP.FP_DIR_PCT;
  const fpMax = isSalarie ? PP.FP_MAX : PP.FP_DIR_MAX;
  r.profExp_annual = Math.min(annualGross * fpPct, fpMax);
  r.profExp = r.profExp_annual / 12;

  // Гүtape 2: Revenu annuel net imposable
  const revNetImposable = annualGross - r.profExp_annual;

  // Гүtape 3: BarГЁme 1 (isolГ©) ou BarГЁme 2 (quotient conjugal)
  const isBareme2 = (emp.civil === 'married_1'); // conjoint sans revenus
  let revPrincipal = revNetImposable;
  let revConjoint = 0;
  if (isBareme2) {
    revConjoint = Math.min(revNetImposable * PP.QC_PCT, PP.QC_MAX);
    revPrincipal = revNetImposable - revConjoint;
  }

  // Гүtape 4: Calcul impГҙt progressif annuel (sur revenu principal)
  const calcImpotAnnuel = (rev) => {
    let impot = 0; let reste = Math.max(0, rev);
    let prev = 0;
    for (const tr of PP.TRANCHES) {
      const tranche = Math.min(reste, tr.lim - prev);
      impot += tranche * tr.rate;
      reste -= tranche;
      prev = tr.lim;
      if (reste <= 0) break;
    }
    return impot;
  };

  let impotAnnuel = calcImpotAnnuel(revPrincipal);
  if (isBareme2 && revConjoint > 0) {
    impotAnnuel += calcImpotAnnuel(revConjoint);
  }

  // Гүtape 5: DГ©duction quotitГ© exemptГ©e d'impГҙt
  const quotiteExempt = PP.EXEMPT * (isBareme2 ? 2 : 1);
  const reductionExempt = calcImpotAnnuel(quotiteExempt);
  impotAnnuel -= reductionExempt;

  // Гүtape 6: RГ©ductions annuelles charges de famille
  let redFam = 0;
  const ch = emp.depChildren || 0;
  if (ch > 0 && ch <= 5) redFam += PP.RED.enfants[ch];
  else if (ch > 5) redFam += PP.RED.enfants[5] + (ch - 5) * PP.RED.enfantX;
  if (emp.handiChildren > 0) redFam += emp.handiChildren * PP.RED.handicap;
  if (emp.civil === 'single' && ch === 0) redFam += PP.RED.isolee;
  if ((emp.civil === 'single' || emp.civil === 'widowed') && ch > 0) redFam += PP.RED.veuf_enfant;
  // Ascendants вүҘ 65 ans Г  charge (Art. 132 CIR 92 вҖ” revenus nets < 3.820вӮ¬)
  const depAsc = emp.depAscendant || 0;
  const depAscHandi = emp.depAscendantHandi || 0;
  if (depAsc > 0) redFam += depAsc * PP.RED.ascendant65;
  if (depAscHandi > 0) redFam += depAscHandi * PP.RED.ascendant65_handi;
  // Conjoint handicapГ© (Art. 132 CIR вҖ” supplГ©ment quotitГ© exemptГ©e)
  if (emp.conjointHandicap) redFam += PP.RED.handicap;
  // Autres personnes Г  charge (Art. 136 CIR вҖ” max 3.820вӮ¬ revenus nets)
  const depAutres = emp.depAutres || 0;
  if (depAutres > 0) redFam += depAutres * PP.RED.isolee; // mГӘme rГ©duction qu'isolГ© par personne
  impotAnnuel -= redFam;

  // Гүtape 7: PrГ©compte mensuel = impГҙt annuel / 12
  r.baseTax = Math.max(0, impotAnnuel) / 12;
  r.famRed = redFam / 12;
  r.taxNet = revNetImposable / 12;
  r.tax = Math.max(0, r.baseTax);
  // в”Җв”Җ Bonus Г  l'emploi FISCAL (rГ©duction prГ©compte professionnel) в”Җв”Җ
  // 33,14% du volet A + 52,54% du volet B (depuis 01/04/2024)
  r.empBonusFiscA = r.empBonusA * 0.3314;
  r.empBonusFiscB = r.empBonusB * 0.5254;
  r.empBonusFisc = r.empBonusFiscA + r.empBonusFiscB;
  r.tax = Math.max(0, r.tax - r.empBonusFisc);

  // Special SS contribution (Art. 106-112 Loi-programme 30/12/1988)
  // BarГЁme trimestriel вҖ” retenue mensuelle = 1/3 du montant trimestriel
  // DiffГ©rent pour isolГ©s vs mГ©nages avec 2 revenus
  // Source: socialsecurity.be + Securex montants-socio-juridiques 2026
  r.css = 0;
  const grossTrim = r.gross * 3; // salaire trimestriel
  const grossTrimOuv = isOuvrier ? grossTrim * 1.08 : grossTrim;
  // Calcul trimestriel puis division par 3
  if (emp.civil === 'married_2' || emp.civil === 'cohabit') {
    // MГүNAGE 2 REVENUS
    if (grossTrimOuv <= 5836.14) r.css = 0;
    else if (grossTrimOuv <= 6570.54) r.css = Math.max(9.30, (grossTrimOuv - 5836.14) * 0.076) / 3;
    else if (grossTrimOuv <= 18116.46) r.css = Math.min(51.64, 18.60 + (grossTrimOuv - 6570.54) * 0.011) / 3;
    else r.css = 51.64 / 3;
    // Plafond mensuel mГ©nage 2 revenus = 51.64вӮ¬/trim = 17.21вӮ¬/mois
    r.css = Math.min(r.css, 51.64 / 3);
  } else {
    // ISOLГү / conjoint SANS revenus
    if (grossTrimOuv <= 5836.14) r.css = 0;
    else if (grossTrimOuv <= 6570.54) r.css = (grossTrimOuv - 5836.14) * 0.076 / 3;
    else if (grossTrimOuv <= 18116.46) r.css = Math.min(60.94, 18.60 + (grossTrimOuv - 6570.54) * 0.011) / 3;
    else r.css = 60.94 / 3;
    // Plafond mensuel isolГ© = 60.94вӮ¬/trim = 20.31вӮ¬/mois
    r.css = Math.min(r.css, 60.94 / 3);
  }
  r.css = Math.round(r.css * 100) / 100;
  r.cssTrimMax = (emp.civil === 'married_2' || emp.civil === 'cohabit') ? 154.92 : 182.82;
  r.cssAnnuelMax = (emp.civil === 'married_2' || emp.civil === 'cohabit') ? 619.68 : 731.28;

  r.mvDays = per.days || Math.round(LEGAL.WD);
  r.mvWorker = r.mvDays * (emp.mvW || 0);
  r.mvEmployer = r.mvDays * (emp.mvE || 0);
  r.transport = 0; r.transportDetail = '';
  const cDist = parseFloat(emp.commDist) || 0;
  const cMonth = parseFloat(emp.commMonth) || 0;
  const cType = emp.commType || 'none';
  const wDays = per.days || 21;
  if (cType === 'train' && cMonth > 0) {
    // SNCB: intervention obligatoire 75% abonnement (CCT 19/9 du 26/03/2004)
    r.transport = cMonth * 0.75;
    r.transportDetail = `Train: 75% Г— ${fmt(cMonth)} = ${fmt(r.transport)}`;
  } else if (cType === 'bus' && cMonth > 0) {
    // Transport en commun autre: intervention = prix abo SNCB mГӘme distance (CCT 19/9)
    r.transport = cMonth * 0.75;
    r.transportDetail = `Bus/Tram: 75% Г— ${fmt(cMonth)} = ${fmt(r.transport)}`;
  } else if (cType === 'bike' && cDist > 0) {
    // VГ©lo: 0,27 вӮ¬/km A/R (2026) вҖ” exonГ©rГ© ONSS et IPP
    r.transport = cDist * 2 * wDays * 0.27;
    r.transportDetail = `VГ©lo: ${cDist}km Г— 2 Г— ${wDays}j Г— 0,27вӮ¬ = ${fmt(r.transport)}`;
  } else if (cType === 'car' && cDist > 0) {
    // Voiture privГ©e: pas d'obligation lГ©gale sauf CCT sectorielle
    // Si employeur intervient: exonГ©ration ONSS max 490вӮ¬/an (2026) = 40,83вӮ¬/mois
    // Calcul forfaitaire courant: barГЁme SNCB pour distance Г©quivalente
    r.transport = Math.min(40.83, cDist * 0.15 * wDays); // estimation
    r.transportDetail = `Voiture: ${cDist}km, interv. max exonГ©rГ©e ${fmt(r.transport)}/mois`;
  } else if (cType === 'carpool' && cDist > 0) {
    r.transport = Math.min(40.83, cDist * 0.15 * wDays);
    r.transportDetail = `Covoiturage: idem voiture`;
  } else if (cType === 'mixed' && cMonth > 0) {
    // CombinГ©: train + vГ©lo possible
    r.transport = cMonth * 0.75 + (cDist > 0 ? cDist * 2 * wDays * 0.27 : 0);
    r.transportDetail = `CombinГ©: train ${fmt(cMonth * 0.75)} + vГ©lo ${fmt(cDist * 2 * wDays * 0.27)}`;
  }
  r.expense = emp.expense || 0;
  r.garnish = per.garnish || 0;
  r.advance = per.advance || 0;
  r.otherDed = per.otherDed || 0;
  // в”Җв”Җ PP VOLONTAIRE (Art. 275В§1 CIR 92 + AR/PP Art. 88) в”Җв”Җ
  // Le travailleur peut demander par Г©crit Г  l'employeur de retenir un PP supplГ©mentaire
  // au-delГ  du minimum lГ©gal. RГ©cupГ©rable via dГ©claration IPP si trop-retenu.
  // L'employeur est tenu de reverser l'intГ©gralitГ© au SPF Finances.
  // Base: AR 09/01/2024 fixant les barГЁmes de PP вҖ” dispense n'affecte pas ce montant.
  r.ppVolontaire = per.ppVolontaire || 0;

  // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
  //  ГүLГүMENTS FISCAUX COMPLETS вҖ” Art. CIR 92 / Loi ONSS 27/06/1969
  // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

  // в”Җв”Җ 1. DOUBLE PГүCULE VACANCES (EmployГ©s вҖ” payГ© par employeur) в”Җв”Җ
  // Art. 19 В§2 AR 28/11/1969 вҖ” ONSS sur 2ГЁme partie (7%) uniquement
  // Double pГ©cule = 92% du brut (85% = 1ГЁre partie + 7% = 2ГЁme partie)
  // 2ГЁme partie soumise ONSS trav 13,07% + cotisation spГ©ciale 1%
  r.doublePecule = per.doublePecule || 0;
  r.dpOnss = 0; r.dpCotisSpec = 0;
  if (r.doublePecule > 0) {
    const dp2 = r.doublePecule * (7/92); // extraire la 2ГЁme partie
    r.dpOnss = dp2 * 0.1307;      // ONSS travailleur sur 2ГЁ partie
    r.dpCotisSpec = dp2 * 0.01;    // cotisation spГ©ciale 1%
  }

  // в”Җв”Җ 2. PГүCULE VACANCES DE DГүPART (Art. 46 Loi 12/04/1965) в”Җв”Җ
  // PayГ© lors de la sortie de service вҖ” simple + double anticipГ©
  // Soumis ONSS 13,07% sur totalitГ©
  r.peculeDepart = per.peculeDepart || 0;
  r.pdOnss = r.peculeDepart > 0 ? r.peculeDepart * 0.1307 : 0;

  // в”Җв”Җ 3. PRIME D'ANCIENNETГү (Art. 19 В§2 14В° AR ONSS) в”Җв”Җ
  // ExonГ©rГ©e ONSS et IPP si: 1Г— entre 25-35 ans anc. et 1Г— вүҘ 35 ans anc.
  // Plafond 2026: max 1Г— brut mensuel ou fraction (prorata)
  // Montant max exonГ©rГ©: employГ© = 1 mois brut, ouvrier = idem
  r.primeAnciennete = per.primeAnciennete || 0;
  const ancAns = emp.anciennete || 0;
  const primeAncExo = (ancAns >= 25) ? Math.min(r.primeAnciennete, emp.monthlySalary) : 0;
  r.primeAncTaxable = Math.max(0, r.primeAnciennete - primeAncExo);
  r.primeAncExoneree = primeAncExo;

  // в”Җв”Җ 4. PRIME DE NAISSANCE / MARIAGE / ГүVГүNEMENT (Circ. ONSS 2024/1) в”Җв”Җ
  // ExonГ©rГ©e ONSS si вүӨ plafond (naissance: coutume, mariage: idem)
  // ConsidГ©rГ© comme avantage social si modique et liГ© Г  Г©vГ©nement
  r.primeNaissance = per.primeNaissance || 0;

  // в”Җв”Җ 5. PRIME D'INNOVATION (Art. 38 В§1er 25В° CIR 92) в”Җв”Җ
  // ExonГ©rГ©e IPP si вүӨ 1 mois brut et вүӨ 1Г— par travailleur
  // Soumise ONSS mais exonГ©rГ©e fiscalement
  r.primeInnovation = per.primeInnovation || 0;

  // в”Җв”Җ 6. INDEMNITГү TГүLГүTRAVAIL (Circ. 2021/C/20 du 26/02/2021) в”Җв”Җ
  // Max 154,74вӮ¬/mois (montant 2026 вҖ” indexГ© chaque annГ©e)
  // ExonГ©rГ©e ONSS et IPP si structurel (min 1 jour/semaine rГ©gulier)
  // Couvre: chauffage, Г©lectricitГ©, petit matГ©riel, amortissement mobilier
  r.indemTeletravail = Math.min(per.indemTeletravail || 0, 154.74);

  // в”Җв”Җ 7. INDEMNITГү FRAIS DE BUREAU (AR/CIR92 Art. 31) в”Җв”Җ
  // Frais propres de l'employeur вҖ” exonГ©rГ©s si justifiГ©s ou forfaitaires
  // Forfait bureau: max 10% brut (tolГ©rance admin. вҖ” non cumulable tГ©lГ©travail)
  r.indemBureau = per.indemBureau || 0;

  // в”Җв”Җ 8. PENSION COMPLГүMENTAIRE вҖ” Retenue personnelle (Loi 28/04/2003 LPC) в”Җв”Җ
  // Retenue sur salaire = cotisation personnelle du travailleur
  // DГ©ductible fiscalement (Art. 145/1 CIR вҖ” rГ©duction 30% avec plafond)
  // Soumise ONSS travailleur (base de calcul ONSS)
  // Cotisation Wijninckx вҖ” 12,5% depuis 2026 (Loi 18/12/2025 M.B. 30/12/2025)
  // Applicable si pension lГ©gale + compl. > pension max secteur public (97.548вӮ¬/an)
  r.pensionCompl = per.pensionCompl || 0;

  // в”Җв”Җ 9. RETENUE SYNDICALE (Art. 23 Loi 12/04/1965) в”Җв”Җ
  // Volontaire вҖ” transmise au syndicat. Pas ONSS, rГ©duction fiscale partielle
  r.retSyndicale = per.retSyndicale || 0;

  // в”Җв”Җ 10. PENSION ALIMENTAIRE (Art. 1409-1412 Code judiciaire) в”Җв”Җ
  // Saisie prioritaire вҖ” avant les autres saisies, sans barГЁme
  r.saisieAlim = per.saisieAlim || 0;

  // в”Җв”Җ 11. RГүDUCTION PP HEURES SUPPLГүMENTAIRES (Art. 154bis CIR 92) в”Җв”Җ
  // Travailleur: rГ©duction PP sur sursalaire (50% ou 100%)
  // Max 180h/an (2026 вҖ” Art.154bis В§3 CIR вҖ” Accord Arizona structurel)
  // Horeca: 360h | Construction+enregistrement: 180h
  // Employeur: dispense versement PP 32,19% (Art. 275/1 CIR)
  // Applicable sur heures au-delГ  de 9h/j ou 38h/sem (ou limite secteur)
  const hsfisc = per.heuresSupFisc || 0;
  r.heuresSupFisc = hsfisc;
  const sursalaire = hsfisc * hr * 0.5; // sursalaire = 50% du taux horaire normal
  // RГ©duction travailleur: 66,81% du PP sur le sursalaire (taux barГЁme 1 Art.154bis)
  // ou 57,75% selon barГЁme 2
  r.redPPHeuresSup = sursalaire > 0 ? Math.round(sursalaire * 0.6681 * 100) / 100 : 0;
  r.tax = Math.max(0, r.tax - r.redPPHeuresSup);

  // в”Җв”Җ 12. DISPENSE VERSEMENT PP NUIT/ГүQUIPES (Art. 275/5 CIR 92) в”Җв”Җ
  // Employeur: dispense de versement PP = 22,8% (travail en Г©quipe/nuit)
  // Ne change pas le net du travailleur, rГ©duit le coГ»t employeur
  r.dispensePPNuit = (per.nightH || 0) > 0 ? r.tax * 0.228 : 0;

  // в”Җв”Җ 13. PP ГҖ TAUX EXCEPTIONNEL вҖ” Double pГ©cule & 13ГЁ mois в”Җв”Җ
  // (AR 09/01/2024 annexe III вҖ” BarГЁmes prГ©compte professionnel)
  // Double pГ©cule vacances: taxГ© Г  taux fixe (pas barГЁme progressif)
  //   Taux = basГ© sur rГ©munГ©ration annuelle brute:
  //   вүӨ 17.280вӮ¬: 0% | вүӨ 32.280вӮ¬: 19,17% | вүӨ 43.380вӮ¬: 23,22% | > 43.380вӮ¬: 30,28%
  // 13ГЁ mois: taux fixe idem (annexe III AR)
  // IndemnitГ© de dГ©part/prГ©avis: taux fixe selon rГ©munГ©ration annuelle
  // NB: ces taux s'appliquent sur le MONTANT EXCEPTIONNEL, pas le salaire mensuel
  r.ppTauxExcep = 0; r.ppTauxExcepRate = 0;
  const typeSpec = per.typeSpecial || 'normal';
  if (typeSpec === 'doublePecule' || typeSpec === 'y13' || typeSpec === 'depart' || typeSpec === 'preavis') {
    const annBrut = r.base * 12;
    if (annBrut <= 17280) r.ppTauxExcepRate = 0;
    else if (annBrut <= 32280) r.ppTauxExcepRate = 0.1917;
    else if (annBrut <= 43380) r.ppTauxExcepRate = 0.2322;
    else r.ppTauxExcepRate = 0.3028;
    // Appliquer sur le montant exceptionnel
    const montantExcep = (typeSpec === 'doublePecule' ? r.doublePecule : 0)
      + (typeSpec === 'y13' ? r.y13 : 0)
      + (typeSpec === 'depart' ? r.peculeDepart : 0)
      + (typeSpec === 'preavis' ? (per.indemPreavis || 0) : 0);
    r.ppTauxExcep = montantExcep * r.ppTauxExcepRate;
    r.tax += r.ppTauxExcep;
  }

  // в”Җв”Җ 14. JOURS FГүRIГүS PAYГүS (Loi 04/01/1974 + AR 18/04/1974) в”Җв”Җ
  // 10 jours fГ©riГ©s lГ©gaux/an (Belgique) вҖ” payГ©s par l'employeur
  // Ouvrier: salaire journalier normal (inclus dans les jours prestГ©s si travaillГ©s)
  // EmployГ©: salaire mensuel normal (pas d'impact sur calcul mensuel)
  // Jour fГ©riГ© travaillГ©: supplГ©ment 200% (dГ©jГ  couvert par sundayH si encodГ©)
  r.joursFeries = per.joursFeries || 0; // nombre encodГ© dans le mois

  // в”Җв”Җ 15. PETIT CHГ”MAGE / CONGГү DE CIRCONSTANCE (AR 28/08/1963) в”Җв”Җ
  // Salaire normal maintenu pour Г©vГ©nements familiaux:
  // Mariage travailleur: 2 jours | DГ©cГЁs conjoint/enfant: 3 jours
  // Naissance enfant (co-parent): 15 jours | Communion: 1 jour
  // DГ©mГ©nagement: 1 jour | Comparution tribunal: nГ©cessaire
  r.petitChomage = per.petitChomage || 0; // nombre jours
  r.petitChomageVal = r.petitChomage * (r.base / LEGAL.WD); // valeur = salaire/jour

  // в”Җв”Җ 16. ГүCO-CHГҲQUES (CCT 98 du 20/02/2009 вҖ” CNT) в”Җв”Җ
  // Max 250вӮ¬/an par travailleur temps plein (prorata temps partiel)
  // ExonГ©rГ©s ONSS et IPP si conditions respectГ©es (pas en remplacement rГ©mun.)
  // Uniquement Г©lectroniques depuis 2024
  // Non inclus dans le brut, pas de retenue вҖ” coГ»t employeur pur
  r.ecoCheques = per.ecoCheques || 0;

  // в”Җв”Җ 17. CADEAUX & AVANTAGES SOCIAUX (Circ. ONSS + Art. 38/11 CIR) в”Җв”Җ
  // ExonГ©rГ©s ONSS+IPP si: NoГ«l/Nouvel An вүӨ 40вӮ¬ + 40вӮ¬/enfant | Mariage вүӨ 245вӮ¬
  // Saint-Nicolas вүӨ 40вӮ¬/enfant | Retraite вүӨ 40вӮ¬/annГ©e service (max 40 ans)
  r.cadeaux = per.cadeaux || 0;

  // в”Җв”Җ 18. BUDGET MOBILITГү (Loi 17/03/2019 modifiГ© 01/01/2022) в”Җв”Җ
  // Alternative Г  la voiture de sociГ©tГ© вҖ” 3 piliers:
  // Pilier 1: voiture plus Г©cologique (ATN rГ©duit)
  // Pilier 2: mobilitГ© durable (transport en commun, vГ©lo, logement) вҖ” exonГ©rГ© ONSS+IPP
  // Pilier 3: solde en cash вҖ” cotisation spГ©ciale 38,07% (employeur + travailleur)
  // Montant = TCO annuel voiture de sociГ©tГ© (1/5 Г— catalogue Г— coeff. Гўge + carburant + CO2)
  r.budgetMobilite = per.budgetMobilite || 0;
  r.budgetMobPilier2 = per.budgetMobP2 || 0; // part exonГ©rГ©e
  r.budgetMobPilier3 = per.budgetMobP3 || 0; // part cash вҶ’ cotisation 38,07%
  r.budgetMobCotis38 = r.budgetMobPilier3 * 0.3807;

  // в”Җв”Җ 19. RГүDUCTIONS GROUPES-CIBLES EMPLOYEUR (AR Groupes-cibles) в”Җв”Җ
  // RГ©ductions ONSS patronales ciblГ©es вҖ” calculГ©es AUTOMATIQUEMENT
  //
  // в•җв•җв•җ PREMIER ENGAGEMENT (AR 16/05/2003 + RГ©forme 01/04/2026) в•җв•җв•җ
  // Art. 336-353 Loi-programme 24/12/2002
  // Source: ONSS instructions T1/2026 + SPF Emploi
  //
  // AVANT 01/04/2026:
  //   1er employГ©: exonГ©ration totale ONSS patronal (durГ©e illimitГ©e depuis 2016)
  //   2ГЁ employГ©: forfait trimestriel 1.550вӮ¬ T1-T5, 1.050вӮ¬ T6-T9, 450вӮ¬ T10-T13
  //   3ГЁ employГ©: forfait trimestriel 1.050вӮ¬ T1-T5, 1.050вӮ¬ T6-T9, 450вӮ¬ T10-T13
  //   4ГЁ employГ©: forfait trimestriel 1.050вӮ¬ T1-T5, 1.050вӮ¬ T6-T9, 450вӮ¬ T10-T13
  //   5ГЁ employГ©: forfait trimestriel 1.050вӮ¬ T1-T5, 1.050вӮ¬ T6-T9, 450вӮ¬ T10-T13
  //   6ГЁ employГ©: forfait trimestriel 1.050вӮ¬ T1-T5, 1.050вӮ¬ T6-T9, 450вӮ¬ T10-T13
  //
  // APRГҲS 01/04/2026 (RГ©forme budget fГ©dГ©ral):
  //   1er employГ©: max 3.100вӮ¬ вҶ’ rГ©duit Г  2.000вӮ¬/trimestre (plafonnГ©)
  //   2ГЁ employГ©: inchangГ©
  //   3ГЁ employГ©: inchangГ©
  //   4ГЁ-5ГЁ-6ГЁ: RГүINTRODUITS (supprimГ©s en 2025, rГ©tablis 04/2026)
  //
  // ParamГЁtre: emp.nrEngagement = rang d'engagement (1 = 1er, 2 = 2ГЁ, etc.)
  // ParamГЁtre: emp.engagementTrimestre = trimestre courant depuis engagement (1-13+)

  const PREMIER_ENG = {
    // Montants trimestriels par rang et par pГ©riode (trimestres depuis engagement)
    // Format: [T1-T5, T6-T9, T10-T13, T14+]
    1: { label: '1er employГ©', amounts: [2000, 2000, 2000, 2000], note: 'IllimitГ© (plafonnГ© 2.000вӮ¬/trim. depuis 04/2026)' },
    2: { label: '2ГЁ employГ©', amounts: [1550, 1050, 450, 0], note: '13 trimestres max' },
    3: { label: '3ГЁ employГ©', amounts: [1050, 1050, 450, 0], note: '13 trimestres max' },
    4: { label: '4ГЁ employГ©', amounts: [1050, 1050, 450, 0], note: 'RГ©introduit 04/2026' },
    5: { label: '5ГЁ employГ©', amounts: [1050, 1050, 450, 0], note: 'RГ©introduit 04/2026' },
    6: { label: '6ГЁ employГ©', amounts: [1050, 1050, 450, 0], note: 'RГ©introduit 04/2026' },
  };

  r.redGCPremier = 0; r.redGCPremierLabel = ''; r.redGCPremierNote = '';
  const nrEng = emp.nrEngagement || 0;
  const engTrim = emp.engagementTrimestre || 1;
  if (nrEng >= 1 && nrEng <= 6) {
    const pe = PREMIER_ENG[nrEng];
    let trimIdx = 0;
    if (engTrim <= 5) trimIdx = 0;
    else if (engTrim <= 9) trimIdx = 1;
    else if (engTrim <= 13) trimIdx = 2;
    else trimIdx = 3;
    const trimAmount = pe.amounts[trimIdx];
    // Mensualiser le montant trimestriel
    r.redGCPremier = Math.round(trimAmount / 3 * 100) / 100;
    // Pour le 1er employГ©: ne peut pas dГ©passer la cotisation patronale effective
    if (nrEng === 1) r.redGCPremier = Math.min(r.redGCPremier, r.onssE + r.redStructMois);
    r.redGCPremierLabel = pe.label;
    r.redGCPremierNote = `${pe.label}: ${fmt(trimAmount)}/trim. (T${engTrim}) вҖ” ${pe.note}`;
  }

  // Travailleurs ГўgГ©s вүҘ 55 ans (AR 19/12/2001 вҖ” Activation 55+)
  // RГ©duction trimestrielle: 1.150вӮ¬ si вүҘ 55 ans + salaire < 14.640,83вӮ¬/trim.
  r.redGCAge = per.redGCAge || 0;
  // Jeunes < 26 ans peu qualifiГ©s (AR Activation jeunes)
  // RГ©duction trimestrielle: 1.500вӮ¬ (trГЁs peu qualifiГ©) ou 1.150вӮ¬ (peu qualifiГ©)
  r.redGCJeune = per.redGCJeune || 0;
  // Travailleurs handicapГ©s
  r.redGCHandicap = per.redGCHandicap || 0;
  r.redGCTotal = r.redGCPremier + r.redGCAge + r.redGCJeune + r.redGCHandicap;

  // в”Җв”Җ 20. COTISATION SPГүCIALE ONSS MODГүRATION SALARIALE (Loi 1996) в”Җв”Җ
  // DГ©jГ  incluse dans le taux ONSS_E global via ONSS_SECTEUR
  // 5,67% sur la masse salariale (employeur) вҖ” pas travailleur

  // в”Җв”Җ 21. ALLOCATION DE TRAVAIL ONEM вҖ” ACTIVATION (AR 19/12/2001 + RГ©gional) в”Җв”Җ
  // MГ©canisme: le travailleur reГ§oit une allocation de l'ONEM via CAPAC/syndicat.
  // L'employeur DГүDUIT ce montant du salaire net Г  payer.
  // Le travailleur touche: salaire net (employeur) + allocation ONEM = rГ©munГ©ration totale.
  // вҶ’ Le coГ»t rГ©el de l'employeur baisse du montant de l'allocation.
  //
  // Types d'allocations de travail:
  // Activa.brussels (Actiris): max вӮ¬350/mois Г— 12 mois вҖ” DE вүҘ 12 mois, rГ©sid. Bruxelles
  // Activa.brussels Jeunes: вӮ¬350/mois Г— 6 mois вҖ” DE < 30 ans, вүҘ 6 mois
  // Impulsion Wallonie: вӮ¬500/mois Г— 24-36 mois вҖ” via FOREM/SPW
  // SINE (Г©conomie sociale): variable
  //
  // Traitement fiscal: l'allocation de travail est un revenu de remplacement pour le travailleur
  // вҶ’ Soumise au prГ©compte professionnel (retenue par ONEM/CAPAC)
  // вҶ’ NON soumise ONSS (pas de rГ©munГ©ration au sens ONSS)
  // вҶ’ L'employeur ne la dГ©clare PAS en DmfA (c'est l'ONEM qui dГ©clare)
  //
  // Sur la fiche de paie: mention "pour mГ©moire" вҖ” dГ©duit du coГ»t employeur
  const allocType = per.allocTravailType || 'none';
  r.allocTravail = per.allocTravail || 0;
  r.allocTravailType = allocType;
  // Montants standards par type (si pas de montant custom)
  if (r.allocTravail === 0 && allocType !== 'none') {
    const ALLOC_MONTANTS = {
      'activa_bxl': 350,       // Activa.brussels: вӮ¬350/mois
      'activa_jeune': 350,     // Activa Jeunes: вӮ¬350/mois
      'impulsion_wal': 500,    // Impulsion Wallonie: вӮ¬500/mois
      'impulsion55': 500,      // Impulsion 55+: вӮ¬500/mois
      'sine': 500,             // SINE: вӮ¬500/mois (variable)
      'vdab': 0,               // Flandre: pas d'allocation trav. (prime directe employeur)
    };
    r.allocTravail = ALLOC_MONTANTS[allocType] || 0;
  }
  r.allocTravailLabel = {
    'activa_bxl': 'Activa.brussels (Actiris)',
    'activa_jeune': 'Activa Jeunes <30 (Actiris)',
    'impulsion_wal': 'Impulsion Wallonie (FOREM)',
    'impulsion55': 'Impulsion 55+ (FOREM)',
    'sine': 'SINE (Г©conomie sociale)',
    'vdab': 'Groupe-cible flamand (VDAB)',
  }[allocType] || '';

  // в”Җв”Җ 14. FLEXI-JOB (Art. 3 Loi 16/11/2015 вҖ” modifiГ© 01/01/2024) в”Җв”Җ
  // Conditions: emploi principal min. 4/5 (T-3) OU pensionnГ©
  // Secteurs: horeca CP302, commerce CP201/202/311, soins CP318/330/331/332,
  //   boulangerie CP118.03, agriculture CP144/145, intГ©rim CP322, sport, culture...
  // Travailleur: 0% ONSS, 0% PP (exonГ©rГ© si вүӨ 12.000вӮ¬/an)
  // Employeur: 28% cotisation patronale spГ©ciale (Art.38В§3ter Loi 29/06/1981)
  // Flexi-salaire min: 12,29вӮ¬/h + 7,67% flexi-pГ©cule vacances (2026)
  // Plafond IPP: 12.000вӮ¬/an (pensionnГ©s: illimitГ©)
  // Dimona: type "FLX" | DmfA: code "050"
  r.isFlexiJob = (emp.contract === 'flexi');
  if (r.isFlexiJob) {
    const flexiMinH = 12.29;
    const flexiH = per.days * ((emp.whWeek || 10) / 5);
    const flexiTauxH = Math.max(flexiMinH, (emp.monthlySalary || 0) / ((emp.whWeek || 10) * 4.33));
    r.flexiSalaireH = flexiTauxH;
    r.flexiHeures = flexiH;
    r.flexiBrut = Math.round(flexiH * flexiTauxH * 100) / 100;
    r.flexiPecule = Math.round(r.flexiBrut * 0.0767 * 100) / 100;
    r.flexiOnssPatronal = Math.round((r.flexiBrut + r.flexiPecule) * 0.28 * 100) / 100;
    r.gross = r.flexiBrut + r.flexiPecule;
    r.base = r.flexiBrut;
    r.onssW = 0; r.onssNet = 0; r.empBonus = 0; r.empBonusA = 0; r.empBonusB = 0;
    r.tax = 0; r.css = 0; r.ppVolontaire = 0; r.ppTauxExcep = 0; r.ppTauxExcepRate = 0;
    r.onssE = r.flexiOnssPatronal; r.redStructMois = 0; r.redStruct = 0;
    r.totalDed = per.advance || 0;
    r.net = r.gross - r.totalDed;
    r.costTotal = r.gross + r.flexiOnssPatronal;
    r.flexiNet = r.net;
    return r;
  }

  // в”Җв”Җ 15. ГүTUDIANT (Art. 17bis AR ONSS) в”Җв”Җ
  // Max 650h/an (2026 вҖ” Annexe III PP + Art.17bis AR 28/11/1969): cotisation solidaritГ© 2,71% (trav) + 5,42% (empl)
  // Au-delГ : ONSS normal. Pas de PP si вүӨ 7.340вӮ¬/an net imposable
  r.isStudent = (emp.contract === 'etudiant');
  if (r.isStudent) {
    r.studentOnssW = Math.round(r.gross * 0.0271 * 100) / 100; // 2,71%
    r.studentOnssE = Math.round(r.gross * 0.0542 * 100) / 100; // 5,42%
    r.onssW = r.studentOnssW; r.onssNet = r.studentOnssW;
    r.onssE = r.studentOnssE;
    r.empBonus = 0; r.empBonusA = 0; r.empBonusB = 0;
    r.redStructMois = 0; r.redStruct = 0;
    // PP = 0 si revenu annuel net вүӨ 7.340вӮ¬
    if (r.gross * 12 <= 7340) { r.tax = 0; r.css = 0; }
  }

  // в”Җв”Җ 16. FRAIS PROFESSIONNELS FORFAITAIRES (Art. 51 CIR 92) в”Җв”Җ
  // DГ©jГ  calculГ© ci-dessus: 30% avec plafond (employГ©s et ouvriers)

  // в”Җв”Җ 17. RГүDUCTIONS FAMILIALES (Art. 136-140 CIR 92) в”Җв”Җ
  // DГ©jГ  calculГ© ci-dessus: quotitГ© exemptГ©e par enfant + isolГ© + handicap

  // в”Җв”Җ 18. DISPENSE VERSEMENT PP RECHERCHE (Art. 275/3 CIR 92) в”Җв”Җ
  // 80% du PP pour les chercheurs (diplГҙme Master/Doctorat)
  // Uniquement cГҙtГ© employeur вҖ” ne change pas le net travailleur

  // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
  //  PГүCULE DE VACANCES вҖ” CALCUL AUTOMATIQUE (Sprint 2)
  // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
  // Source: Loi 28/06/1971 + AR 30/03/1967 + ONSS Instructions 2026
  //
  // EMPLOYГүS (payГ© par l'employeur):
  //   Simple: 100% du brut mensuel normal (payГ© pendant les vacances)
  //   Double: 92% du brut mensuel вҶ’ payГ© avant les vacances (gГ©nГ©ralement mai/juin)
  //     - 1ГЁre partie (85%): soumise PP normal
  //     - 2ГЁme partie (7%): soumise ONSS 13,07% + cotisation spГ©ciale 1%
  //   вҶ’ Le simple pГ©cule = salaire normal du mois de vacances (dГ©jГ  dans le brut)
  //
  // OUVRIERS (payГ© par la Caisse de Vacances / ONVA):
  //   Total: 15,38% du brut annuel N-1 (Г  108%)
  //   Simple: 6,80% (7,69% de 108% - cotisation solidaritГ©)
  //   Double: 8,58% (reste)
  //   вҶ’ VersГ© via l'ONVA ou la Caisse sectorielle, PAS par l'employeur
  //   вҶ’ L'employeur paie la cotisation vacances 15,84% trimestrielle Г  l'ONSS
  //
  r.peculeVacCalc = {
    type: isOuvrier ? 'ouvrier' : 'employe',
    brutRef: isOuvrier ? (r.gross * 1.08 * 12) : (emp.monthlySalary || 0), // brut annuel N-1 Г  108% pour ouvriers
    simple: 0,
    double: 0,
    total: 0,
    onss2emePartie: 0,
    cotisSpec1pct: 0,
    ppExcep: 0,
    moisPaiement: isOuvrier ? 'Mai (Caisse de Vacances)' : 'Mai/Juin (Employeur)'
  };
  if (!isOuvrier) {
    // EmployГ©: simple = 1 mois brut (dГ©jГ  inclus dans salaire normal du mois de vacances)
    r.peculeVacCalc.simple = emp.monthlySalary || 0;
    // Double = 92% du brut mensuel
    r.peculeVacCalc.double = (emp.monthlySalary || 0) * 0.92;
    r.peculeVacCalc.total = r.peculeVacCalc.simple + r.peculeVacCalc.double;
    // 2ГЁme partie du double pГ©cule (7/92 du double) вҶ’ ONSS 13,07% + cotis spГ©ciale 1%
    const dp2 = r.peculeVacCalc.double * (7/92);
    r.peculeVacCalc.onss2emePartie = Math.round(dp2 * 0.1307 * 100) / 100;
    r.peculeVacCalc.cotisSpec1pct = Math.round(dp2 * 0.01 * 100) / 100;
    // PP exceptionnel sur le double pГ©cule
    const annBrutDP = (emp.monthlySalary || 0) * 12;
    if (annBrutDP <= 17280) r.peculeVacCalc.ppExcepRate = 0;
    else if (annBrutDP <= 32280) r.peculeVacCalc.ppExcepRate = 0.1917;
    else if (annBrutDP <= 43380) r.peculeVacCalc.ppExcepRate = 0.2322;
    else r.peculeVacCalc.ppExcepRate = 0.3028;
    r.peculeVacCalc.ppExcep = Math.round(r.peculeVacCalc.double * (r.peculeVacCalc.ppExcepRate || 0) * 100) / 100;
  } else {
    // Ouvrier: 15,38% du brut annuel N-1 Г— 108%
    r.peculeVacCalc.simple = Math.round(r.peculeVacCalc.brutRef * 0.0680 * 100) / 100;
    r.peculeVacCalc.double = Math.round(r.peculeVacCalc.brutRef * 0.0858 * 100) / 100;
    r.peculeVacCalc.total = Math.round(r.peculeVacCalc.brutRef * 0.1538 * 100) / 100;
  }

  // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
  //  13ГҲME MOIS / PRIME DE FIN D'ANNГүE вҖ” CALCUL PAR CP (Sprint 2)
  // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
  // Source: CCT sectorielles + AR rendant les CCT obligatoires
  //
  // La prime de fin d'annГ©e n'est PAS une obligation lГ©gale mais conventionnelle.
  // Son montant et ses conditions varient par commission paritaire:
  //
  // CP 200 (employГ©s): 100% du brut mensuel (convention quasi-universelle)
  // CP 124 (construction): calculГ© en % du brut Г— jours prestГ©s
  // CP 302 (horeca): prime = brut mensuel Г— coefficient (Fonds social)
  // CP 330 (soins santГ©): prime = montant fixe indexГ© par Г©chelon
  //
  r.y13Calc = {
    cp: emp.cp || '200',
    moisPaiement: 'DГ©cembre',
    montant: 0,
    onss: 0,
    ppExcep: 0,
    ppExcepRate: 0,
    coГ»tEmployeur: 0,
    methode: ''
  };
  const cpNum = parseInt(emp.cp) || 200;
  if (cpNum === 124) {
    // Construction: 8,33% du brut annuel (via Fonds social)
    r.y13Calc.montant = Math.round((emp.monthlySalary || 0) * 12 * 0.0833 * 100) / 100;
    r.y13Calc.methode = 'CP 124 вҖ” 8,33% brut annuel (Fonds social FBTP)';
  } else if (cpNum === 302) {
    // Horeca: via Fonds social вҖ” environ 1 mois brut
    r.y13Calc.montant = emp.monthlySalary || 0;
    r.y13Calc.methode = 'CP 302 вҖ” Вұ1 mois brut (Fonds social Horeca)';
  } else if (cpNum >= 330 && cpNum <= 332) {
    // Non-marchand santГ©/social: montant fixe indexГ© вүҲ 1 mois
    r.y13Calc.montant = emp.monthlySalary || 0;
    r.y13Calc.methode = 'CP 330-332 вҖ” Montant fixe indexГ© (CCT sectorielle)';
  } else {
    // CP 200 et autres: 1 mois brut (convention quasi-universelle)
    r.y13Calc.montant = emp.monthlySalary || 0;
    r.y13Calc.methode = 'CP ' + cpNum + ' вҖ” 100% brut mensuel (CCT sectorielle)';
  }
  // ONSS sur 13ГЁme mois: 13,07% travailleur
  r.y13Calc.onss = Math.round(r.y13Calc.montant * 0.1307 * 100) / 100;
  // PP exceptionnel (taux fixe selon rГ©munГ©ration annuelle brute)
  const annBrut13 = (emp.monthlySalary || 0) * 12;
  if (annBrut13 <= 17280) r.y13Calc.ppExcepRate = 0;
  else if (annBrut13 <= 32280) r.y13Calc.ppExcepRate = 0.1917;
  else if (annBrut13 <= 43380) r.y13Calc.ppExcepRate = 0.2322;
  else r.y13Calc.ppExcepRate = 0.3028;
  r.y13Calc.ppExcep = Math.round(r.y13Calc.montant * r.y13Calc.ppExcepRate * 100) / 100;
  r.y13Calc.netEstime = Math.round((r.y13Calc.montant - r.y13Calc.onss - r.y13Calc.ppExcep) * 100) / 100;
  r.y13Calc.coГ»tEmployeur = Math.round(r.y13Calc.montant * (1 + (LEGAL.ONSS_SECTEUR[emp.cp]?.e || 0.25)) * 100) / 100;

  // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
  //  TOTALISATION
  // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

  // Total retenues sur le net
  r.totalDed = r.onssNet + r.tax + r.css + r.mvWorker
    + r.garnish + r.advance + r.otherDed + r.ppVolontaire
    + r.atnCar + r.atnAutresTot
    + r.dpOnss + r.dpCotisSpec       // ONSS double pГ©cule
    + r.pdOnss                        // ONSS pГ©cule dГ©part
    + r.pensionCompl                  // retenue pension complГ©mentaire
    + r.retSyndicale                  // retenue syndicale
    + r.saisieAlim                    // pension alimentaire
    + r.budgetMobCotis38;             // budget mobilitГ© pilier 3

  // Net Г  payer
  r.net = r.gross - r.totalDed + r.expense + r.transport
    + r.doublePecule - r.dpOnss - r.dpCotisSpec    // double pГ©cule net
    + r.peculeDepart - r.pdOnss                      // pГ©cule dГ©part net
    + r.primeAncExoneree                              // prime anciennetГ© exonГ©rГ©e
    + r.primeNaissance                                // prime naissance (exo)
    + r.indemTeletravail                              // indemnitГ© tГ©lГ©travail (exo)
    + r.indemBureau                                   // frais bureau (exo)
    + r.petitChomageVal                               // petit chГҙmage (salaire maintenu)
    + r.budgetMobPilier2                             // budget mobilitГ© pilier 2 (exo)
    + r.hsBrutNetTotal;                                // HS volontaires brut=net (exo ONSS+PP)

  // ONSS employeur dГ©jГ  calculГ© ci-dessus (onssE, onssE_rate, onssE_note)
  r.insAT = r.gross * 0.0087;
  // Cotisation vacances annuelles ouvriers (Art. 38 Loi 29/06/1981)
  // 15,84% sur brut Г— 108% вҖ” payГ© via ONSS, versГ© Г  la Caisse de vacances
  // Inclus dans le taux ONSS sectoriel ouvrier mais Г  afficher sГ©parГ©ment
  r.cotisVacOuv = isOuvrier ? onssBase * LEGAL.ONSS_DETAIL_2026.vacances_annuelles_ouvrier : 0;
  // Cotisation patronale pension complГ©mentaire (estimation si retenue personnelle existe)
  r.pensionComplEmpl = r.pensionCompl > 0 ? r.pensionCompl * 2 : 0; // ratio courant 2:1
  r.cotisWijninckx = (r.pensionComplEmpl + r.pensionCompl) * 12 > 32472 ? ((r.pensionComplEmpl + r.pensionCompl) * 12 - 32472) / 12 * 0.125 : 0;
  // Dispenses PP employeur (ne changent pas le net travailleur mais rГ©duisent le coГ»t)
  // Art 275/1 CIR: dispense heures sup = 32,19% du PP retenu sur le sursalaire
  r.dispensePPHSup = sursalaire > 0 ? sursalaire * 0.3219 : 0;
  r.dispensePPTotal = r.dispensePPNuit + r.dispensePPHSup;
  r.costTotal = r.gross + r.onssE + r.mvEmployer + r.expense + r.transport + r.insAT + r.cotCO2
    + r.cotisVacOuv                                     // vacances ouvriers 15,84%
    + r.pensionComplEmpl + r.cotisWijninckx              // pension complГ©mentaire
    + r.doublePecule + r.peculeDepart + r.primeAnciennete + r.primeNaissance + r.primeInnovation
    + r.indemTeletravail + r.indemBureau
    + r.ecoCheques + r.cadeaux                           // Г©co-chГЁques + cadeaux
    + r.budgetMobCotis38                                 // budget mobilitГ© pilier 3
    + r.veloLeasingMois                                   // leasing vГ©lo
    + r.borneRechargeCoГ»t                                 // borne de recharge
    + r.carteCarburantMois                                // carte carburant
    - r.dispensePPTotal                                   // dispenses PP
    - r.redGCTotal                                        // rГ©ductions groupes-cibles
    - r.allocTravail;                                     // allocation travail ONEM (dГ©duit du coГ»t)
  return r;
}

// в”Җв”Җв”Җ XML GENERATORS в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function genDimonaXML(d) {
  const niss=(d.niss||'').replace(/[\.\-\s]/g,"");
  const onss=(d.onss||'').replace(/[\.\-\s]/g,"");
  const vat=(d.vat||'').replace(/[^0-9]/g,"");
  const dimRef='DIM'+Date.now().toString(36).toUpperCase()+Math.random().toString(36).slice(2,5).toUpperCase();
  return `<?xml version="1.0" encoding="UTF-8"?>
<!-- Dimona Declaration вҖ” ONSS / socialsecurity.be -->
<!-- Generee par: Aureus Social Pro вҖ” Aureus IA SPRL -->
<!-- Reference: ${dimRef} -->
<Dimona xmlns="http://www.smals-mvm.be/xml/ns/systemFlux">
  <DimonaDeclaration>
    <EmployerId>
      <NLOSSRegistrationNbr>${onss}</NLOSSRegistrationNbr>
      <CompanyID>${vat}</CompanyID>
    </EmployerId>
    <Feature>
      <CreationDate>${new Date().toISOString().split('T')[0]}</CreationDate>
      <Action>${d.action}</Action>${d.action==='UPDATE'&&d.dimonaP?`
      <DimPeriodId>${d.dimonaP}</DimPeriodId>`:''}
      <Worker>
        <INSS>${niss}</INSS>
        <WorkerName>${d.last||''}</WorkerName>
        <WorkerFirstName>${d.first||''}</WorkerFirstName>
        <BirthDate>${d.birth||''}</BirthDate>
      </Worker>
      <Period>
        <StartingDate>${d.start}</StartingDate>${d.end?`
        <EndingDate>${d.end}</EndingDate>`:''}
      </Period>
      <WorkerType>${d.wtype}</WorkerType>
      <JointCommission>${d.cp||'200'}</JointCommission>${d.hours?`
      <PlannedDaysOrHours>
        <PlannedHoursNbr>${d.hours}</PlannedHoursNbr>
      </PlannedDaysOrHours>`:''}${d.action==='OUT'&&d.reason?`
      <EndingReason>${d.reason}</EndingReason>`:''}${d.wtype==='STU'?`
      <StudentData>
        <MaxHoursPerYear>600</MaxHoursPerYear>
        <SolidarityContribution>YES</SolidarityContribution>
      </StudentData>`:''}${d.wtype==='FLX'?`
      <FlexiJobData>
        <FlexiWage>YES</FlexiWage>
        <SpecialContribution28>YES</SpecialContribution28>
      </FlexiJobData>`:''}${d.wtype==='EXT'?`
      <ExtraData>
        <MaxDaysPerYear>50</MaxDaysPerYear>
        <FlatRateContribution>YES</FlatRateContribution>
      </ExtraData>`:''}
    </Feature>
    <SenderSoftware>AureusSocialPro</SenderSoftware>
    <SenderSoftwareVersion>2026.4</SenderSoftwareVersion>
  </DimonaDeclaration>
</Dimona>`;
}


function genDMFAXML(co, emps, q, y) {
  // DMFA conforme schema XSD ONSS вҖ” socialsecurity.be/TechLib
  // Structure: FormCreation > EmployerDeclaration > WorkerRecord > OccupationRecord > ServiceRecord > RemunRecord + ContributionRecord
  const qStart=new Date(y,(q-1)*3,1);
  const qEnd=new Date(y,q*3,0);
  const fmtDt=d=>`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
  const ref=`DMFAP${String(Math.floor(Math.random()*900000000)+100000000)}${String.fromCharCode(65+Math.floor(Math.random()*26))}`;
  const catEmpl=(co.cp==='330'||co.cp==='331'||co.cp==='332')?'010':'000';
  const nrONSS=(co.onss||'').replace(/[\.\-\s]/g,"")||'0000000000';
  const nrEnt=(co.vat||'').replace(/[^0-9]/g,"")||'0000000000';

  const wrs=emps.map((e,idx)=>{
    const p=calc(e,{days:65},co);
    const niss=(e.niss||'').replace(/[\.\-\s]/g,"");
    const isOuv=(e.statut==='ouvrier');
    const codeTrav=e.dmfaCode||'495';
    const baseONSS=isOuv?p.gross*3*1.08:p.gross*3;
    const wh=e.whWeek||38;
    const daysQ=Math.round((p.mvDays||22)*3);
    const hoursQ=Math.round(daysQ*(wh/5)*100)/100;
    const startD=e.startD||fmtDt(qStart);
    return `    <WorkerRecord>
      <WorkerIdentification>
        <INSS>${niss}</INSS>
        <WorkerName>${e.last||''}</WorkerName>
        <WorkerFirstName>${e.first||''}</WorkerFirstName>
      </WorkerIdentification>
      <WorkerContributionCode>${codeTrav}</WorkerContributionCode>
      <WorkerCategory>${catEmpl}</WorkerCategory>
      <OccupationRecord>
        <OccupationSequenceNbr>${idx+1}</OccupationSequenceNbr>
        <CommissionNbr>${e.cp||'200'}</CommissionNbr>
        <WorkerStatus>${isOuv?'1':'2'}</WorkerStatus>
        <MeanWorkingHoursPerWorker>${wh.toFixed(2)}</MeanWorkingHoursPerWorker>
        <MeanWorkingHoursReferPerson>38.00</MeanWorkingHoursReferPerson>
        <WorkSchedule>${e.regime==='full'?'F':'P'}</WorkSchedule>
        <OccupationStartingDate>${startD}</OccupationStartingDate>
        <OccupationEndingDate>${fmtDt(qEnd)}</OccupationEndingDate>
        <EstablishmentUnitNbr>${nrEnt}</EstablishmentUnitNbr>
        <ServiceRecord>
          <ServiceCode>001</ServiceCode>
          <ServiceNbrDays>${daysQ}</ServiceNbrDays>
          <ServiceNbrHours>${hoursQ.toFixed(2)}</ServiceNbrHours>
        </ServiceRecord>
        <RemunRecord>
          <RemunCode>001</RemunCode>
          <RemunAmount>${(p.gross*3).toFixed(2)}</RemunAmount>
          <RemunFrequency>1</RemunFrequency>
        </RemunRecord>${isOuv?`
        <RemunRecord>
          <RemunCode>010</RemunCode>
          <RemunAmount>${(p.gross*3*0.08).toFixed(2)}</RemunAmount>
          <RemunFrequency>1</RemunFrequency>
        </RemunRecord>`:''}
      </OccupationRecord>
      <ContributionWorkerRecord>
        <ContributionType>001</ContributionType>
        <ContributionBase>${baseONSS.toFixed(2)}</ContributionBase>
        <ContributionPercentage>13.07</ContributionPercentage>
        <ContributionAmount>${(baseONSS*LEGAL.ONSS_W).toFixed(2)}</ContributionAmount>
      </ContributionWorkerRecord>${p.empBonus>0?`
      <DeductionRecord>
        <DeductionType>001</DeductionType>
        <DeductionAmount>${(p.empBonus*3).toFixed(2)}</DeductionAmount>
      </DeductionRecord>`:''}
    </WorkerRecord>`;
  }).join('\n');

  const totW=emps.reduce((s,e)=>{const p=calc(e,{days:65},co);const isO=e.statut==='ouvrier';const b=isO?p.gross*3*1.08:p.gross*3;return s+b*LEGAL.ONSS_W;},0);
  const totE=emps.reduce((s,e)=>{const p=calc(e,{days:65},co);return s+p.onssE*3;},0);
  const totFFE=emps.reduce((s,e)=>{const p=calc(e,{days:65},co);return s+(p.onss_ffe||0)*3;},0);
  const totChT=emps.reduce((s,e)=>{const p=calc(e,{days:65},co);return s+(p.onss_chomTemp||0)*3;},0);
  const totAm=emps.reduce((s,e)=>{const p=calc(e,{days:65},co);return s+(p.onss_amiante||0)*3;},0);
  const totBase=emps.reduce((s,e)=>{const p=calc(e,{days:65},co);const isO=e.statut==='ouvrier';return s+(isO?p.gross*3*1.08:p.gross*3);},0);

  return `<?xml version="1.0" encoding="UTF-8"?>
<!-- DmfAOriginal вҖ” Declaration Multifonctionnelle / Securite Sociale Belge -->
<!-- Schema conforme ONSS вҖ” socialsecurity.be/TechLib -->
<!-- Reference: ${ref} | Trimestre: ${q}/${y} -->
<!-- Genere par: Aureus Social Pro вҖ” Aureus IA SPRL (${AUREUS_INFO.vat}) -->
<DmfAOriginal xmlns="http://www.smals-mvm.be/xml/ns/systemFlux"
              xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance">
  <FormCreation>
    <FormType>DMFA</FormType>
    <FormCreationDate>${fmtDt(new Date())}</FormCreationDate>
    <Reference>${ref}</Reference>
    <FormSubType>ORIGINAL</FormSubType>
    <SenderSoftware>AureusSocialPro</SenderSoftware>
    <SenderSoftwareVersion>2026.4</SenderSoftwareVersion>
    <SenderCompanyID>${nrEnt}</SenderCompanyID>
  </FormCreation>
  <EmployerDeclaration>
    <NLOSSRegistrationNbr>${nrONSS}</NLOSSRegistrationNbr>
    <CompanyID>${nrEnt}</CompanyID>
    <EmployerDenomination>${co.name||''}</EmployerDenomination>
    <LanguageCode>1</LanguageCode>
    <Quarter>${q}</Quarter>
    <Year>${y}</Year>
    <EmployerCategory>${catEmpl}</EmployerCategory>
    <NbrOfWorkers>${emps.length}</NbrOfWorkers>
${wrs}
    <GlobalContribution>
      <ContributionRecord><ContributionType>001</ContributionType><ContributionBase>${totBase.toFixed(2)}</ContributionBase><ContributionAmount>${totE.toFixed(2)}</ContributionAmount></ContributionRecord>
      <ContributionRecord><ContributionType>810</ContributionType><ContributionBase>${totBase.toFixed(2)}</ContributionBase><ContributionAmount>${totFFE.toFixed(2)}</ContributionAmount></ContributionRecord>
      <ContributionRecord><ContributionType>855</ContributionType><ContributionBase>${totBase.toFixed(2)}</ContributionBase><ContributionAmount>${totChT.toFixed(2)}</ContributionAmount></ContributionRecord>
      ${q<=3?`<ContributionRecord><ContributionType>862</ContributionType><ContributionBase>${totBase.toFixed(2)}</ContributionBase><ContributionAmount>${totAm.toFixed(2)}</ContributionAmount></ContributionRecord>`:'<!-- Fonds amiante: non du en T4 -->'}
    </GlobalContribution>
    <DeclarationTotals>
      <TotalWorkerContribution>${totW.toFixed(2)}</TotalWorkerContribution>
      <TotalEmployerContribution>${(totE+totFFE+totChT+totAm).toFixed(2)}</TotalEmployerContribution>
      <TotalContribution>${(totW+totE+totFFE+totChT+totAm).toFixed(2)}</TotalContribution>
    </DeclarationTotals>
  </EmployerDeclaration>
</DmfAOriginal>`;
}

// Genere un accuse de reception (ACRF) simule conforme ONSS
function genDMFATicket(ref,co){
  const ticket='DMFAP'+String(Math.floor(Math.random()*900000000)+100000000)+String.fromCharCode(65+Math.floor(Math.random()*26));
  const fmtDt=d=>`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
  return {ticket,xml:`<?xml version="1.0" encoding="UTF-8"?>
<!-- Accuse de reception (ACRF) вҖ” ONSS -->
<AcknowledgmentOfReceipt>
  <Ticket>${ticket}</Ticket>
  <FormType>DMFA</FormType>
  <Reference>${ref}</Reference>
  <ReceptionDate>${fmtDt(new Date())}</ReceptionDate>
  <ResultCode>1</ResultCode>
  <ResultDescription>Fichier accepte pour traitement</ResultDescription>
  <CompanyID>${(co.vat||'').replace(/[^0-9]/g,"")}</CompanyID>
  <Software>AureusSocialPro v2226.1</Software>
</AcknowledgmentOfReceipt>`};
}

// Genere une notification (DMNO) simulee conforme ONSS
function genDMFANotification(ticket,co,q,y,nW,totC,anomalies){
  const fmtDt=d=>`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
  return `<?xml version="1.0" encoding="UTF-8"?>
<!-- Notification (DMNO) вҖ” ONSS -->
<DmfANotification>
  <FormType>DMFA</FormType>
  <Ticket>${ticket}</Ticket>
  <Quarter>${q}</Quarter><Year>${y}</Year>
  <CompanyID>${(co.vat||'').replace(/[^0-9]/g,"")}</CompanyID>
  <ResultCode>${anomalies.length===0?'1':'1'}</ResultCode>
  <ResultDescription>Declaration acceptee${anomalies.length>0?' avec anomalies':''}</ResultDescription>
  <HandlingDate>${fmtDt(new Date())}</HandlingDate>
  <NbrOfWorkers>${nW}</NbrOfWorkers>
  <TotalContribution>${totC}</TotalContribution>
  ${anomalies.length>0?'<AnomalyReport>'+anomalies.map(a=>'<Anomaly><Zone>'+a.zone+'</Zone><Severity>'+a.sev+'</Severity><Desc>'+a.desc+'</Desc></Anomaly>').join('')+'</AnomalyReport>':'<AnomalyReport/>'}
</DmfANotification>`;
}

function genBelcotax(co, emp, yr, ad) {
  // Belcotax XML вҖ” Format BelcotaxOnWeb SPF Finances
  // Ref: https://financien.belgium.be/fr/e-services/belcotaxonweb
  // 281.10 = salariГ©s | 281.20 = dirigeants | 281.50 = commissions
  const statut = emp.statut === 'dirigeant' ? '20' : '10';
  return `<?xml version="1.0" encoding="UTF-8"?>
<Belcotax xmlns="urn:belcotax:${yr}">
  <Verzending>
    <Aangifte>
      <Taal>FR</Taal>
      <Aangiftetype>281.${statut}</Aangiftetype>
      <AangifteJaar>${yr}</AangifteJaar>
      <Schuldenaar>
        <KBO>${(co.bce||co.vat||'').replace(/[^0-9]/g,"")}</KBO>
        <BTWNr>${(co.vat||'').replace(/[^0-9]/g,"")}</BTWNr>
        <ONSS>${(co.onss||'').replace(/[^0-9]/g,"")}</ONSS>
        <NACECode>${co.nace||''}</NACECode>
        <Naam>${co.name}</Naam>
        <Adres>${co.addr}</Adres>
      </Schuldenaar>
      <Opgave>
        <Verkrijger>
          <INSZ>${(emp.niss||'').replace(/[\.\-\s]/g,"")}</INSZ>
          <Naam>${emp.last}</Naam>
          <Voornaam>${emp.first}</Voornaam>
          <Adres>${emp.addr||''} ${emp.zip||''} ${emp.city||''}</Adres>
          <Geboortedatum>${emp.birth||''}</Geboortedatum>
        </Verkrijger>
        <Bezoldiging>
          <Lonen>${(ad.gross||0).toFixed(2)}</Lonen>
          <RIZIV>${(ad.onss||0).toFixed(2)}</RIZIV>
          <WerkBonus>${(ad.empB||0).toFixed(2)}</WerkBonus>
          <BedrijfsVH>${(ad.tax||0).toFixed(2)}</BedrijfsVH>
          <BijzBijdrSZ>${(ad.css||0).toFixed(2)}</BijzBijdrSZ>
          <Maaltijdcheques aantal="${ad.mvC||0}">${(ad.mvE||0).toFixed(2)}</Maaltijdcheques>
          <Vervoer>${(ad.tr||0).toFixed(2)}</Vervoer>
          <VoertuigVAA>${(ad.atnCar||0).toFixed(2)}</VoertuigVAA>
          <AndereVAA>${(ad.atnAutres||0).toFixed(2)}</AndereVAA>
          <AanvullendPensioen>${(ad.pensionCompl||0).toFixed(2)}</AanvullendPensioen>
          <EigenKosten>${(ad.fraisPropres||0).toFixed(2)}</EigenKosten>
          <EcoCheques>${(ad.ecoCheques||0).toFixed(2)}</EcoCheques>
        </Bezoldiging>
        <Periode><Van>01-01-${yr}</Van><Tot>31-12-${yr}</Tot></Periode>
        <Tewerkstelling>
          <CP>${emp.cp||'200'}</CP>
          <Functie>${emp.fn||''}</Functie>
          <Regime>${emp.regime==='full'?'VT':'DT'}</Regime>
          <Uren>${emp.whWeek||38}</Uren>
        </Tewerkstelling>
      </Opgave>
    </Aangifte>
  </Verzending>
</Belcotax>`;
}

