                ...(res.pensionCompl>0?[{l:"Pension complГ©mentaire (ret. pers.)",m:res.pensionCompl,onss:'вң… Oui',pp:'вқҢ RГ©duc. 30%',ref:"LPC 28/04/2003 + Art.145/1"}]:[]),
