                <td style={{padding:'5px 8px',textAlign:'center',color:x.pp?.includes('вқҢ')?'#16a34a':x.pp?.includes('вң…')?'#dc2626':'#999',fontWeight:600,fontSize:10}}>{x.pp||''}</td>
