function ContratsTravailMod({s,d}){
  const [type,setType]=useState('cdi');
  const [form,setForm]=useState({
    empNom:'',empPrenom:"",empNN:'',empAdresse:'',empNationalite:'Belge',
    fonction:'',salaireBrut:'',debut:'',fin:'',essai:'',
    regime:'38h/semaine',horaire:'Lundi-Vendredi 09:00-17:30',
    lieuTravail:s.co.address||'',
    avantages:'ChГЁques-repas, Eco-chГЁques (si applicable)',
    clauseNonConcurrence:'Non',clauseEcolage:'Non',
  });
  const upd=(k,v)=>setForm(p=>({...p,[k]:v}));
  const sel=CONTRAT_TYPES.find(x=>x.id===type);
  
  const generate=()=>{
    const now=new Date().toLocaleDateString('fr-BE');
    let doc=`CONTRAT DE TRAVAIL\n`;
    doc+=`${sel.l}\n`;
    doc+=`в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n\n`;
    doc+=`ENTRE:\n`;
    doc+=`L'employeur: ${s.co.name}\nSiГЁge: ${s.co.address}\nNВ° BCE: ${s.co.bce||'[BCE]'}\nNВ° ONSS: ${s.co.onss||'[ONSS]'}\nCP: ${s.co.cp||'200'}\n`;
    doc+=`ReprГ©sentГ© par: [Nom du responsable]\n\n`;
    doc+=`ET:\n`;
    doc+=`Le travailleur: ${form.empPrenom} ${form.empNom}\nNN: ${form.empNN}\nDomicile: ${form.empAdresse}\nNationalitГ©: ${form.empNationalite}\n\n`;
    doc+=`IL EST CONVENU CE QUI SUIT:\n\n`;
    doc+=`Art. 1 вҖ” OBJET\nLe travailleur est engagГ© en qualitГ© de: ${form.fonction}\n\n`;
    doc+=`Art. 2 вҖ” DURГүE\n`;
    if(type==='cdi')doc+=`Le prГ©sent contrat est conclu pour une durГ©e indГ©terminГ©e.\n`;
    else if(type==='cdd')doc+=`Le prГ©sent contrat prend cours le ${form.debut} et se termine le ${form.fin}.\n`;
    else if(type==='etudiant')doc+=`Convention Г©tudiante du ${form.debut} au ${form.fin}.\nDans le cadre du contingent de 650h/an (art. 17bis AR 28/11/1969).\n`;
    else if(type==='trav_det')doc+=`Le prГ©sent contrat est conclu pour un travail nettement dГ©fini.\nDescription: [Г  complГ©ter]\nLe contrat prendra fin Г  l'achГЁvement du travail convenu.\n`;
    else if(type==='remplacement')doc+=`Le prГ©sent contrat est conclu en remplacement de [nom travailleur absent]\nabsent(e) pour cause de [motif].\nDurГ©e maximale: 2 ans (art. 11ter loi 03/07/1978).\n`;
    else if(type==='saisonnier')doc+=`Travail saisonnier du ${form.debut} au ${form.fin}.\nMax 65 jours/an (100 jours pour fruits/lГ©gumes). Dimona В« DWD В».\n`;
    else if(type==='occas_horeca')doc+=`Travail occasionnel Horeca du ${form.debut} au ${form.fin}.\nMax 50 jours/an. Forfait ONSS: 8,86вӮ¬/heure.\n`;
    else if(type==='insertion')doc+=`Convention d'immersion professionnelle (CIP) du ${form.debut} au ${form.fin}.\nDurГ©e: max 6 mois, renouvelable 1 fois. IndemnitГ© mensuelle: ${form.salaireBrut}вӮ¬.\nCette convention n'est PAS un contrat de travail.\n`;
    else if(type==='formation_alternance')doc+=`Contrat de formation en alternance du ${form.debut} au ${form.fin}.\n20% formation / 80% entreprise. Allocation selon annГ©e de formation.\n`;
    else if(type==='teletravail_struct')doc+=`Le prГ©sent contrat inclut un avenant de tГ©lГ©travail structurel (CCT nВ°85).\nLieu de tГ©lГ©travail: domicile du travailleur.\nIndemnitГ© forfaitaire de bureau: max 151,70вӮ¬/mois.\n`;
    else if(sel.cat==='independant'){
      doc=`CONVENTION DE COLLABORATION INDГүPENDANTE\n${sel.l}\nв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n\n`;
      doc+=`ENTRE:\nLe donneur d'ordre: ${s.co.name}\nSiГЁge: ${s.co.address}\nNВ° BCE: ${s.co.bce||'[BCE]'}\n\n`;
      doc+=`ET:\nLe prestataire indГ©pendant: ${form.empPrenom} ${form.empNom}\nNВ° BCE: [BCE prestataire]\nNВ° TVA: [TVA prestataire]\nCaisse sociale: [nom caisse]\n\n`;
      doc+=`Art. 1 вҖ” OBJET\nLe prestataire s'engage Г  fournir les services suivants: ${form.fonction}\nEn qualitГ© de: ${sel.l}\n\n`;
      doc+=`Art. 2 вҖ” ABSENCE DE LIEN DE SUBORDINATION\nLe prestataire exerce son activitГ© en toute indГ©pendance.\nIl organise librement son travail, dГ©termine ses horaires et mГ©thodes.\nAucun lien de subordination n'existe entre les parties (Loi 27/12/2006).\n\n`;
      doc+=`Art. 3 вҖ” RГүMUNГүRATION\nHonoraires: ${form.salaireBrut}вӮ¬ [par mois/prestation/heure]\nFacturation: mensuelle, TVA 21%.\nPaiement: 30 jours fin de mois.\n\n`;
      doc+=`Art. 4 вҖ” DURГүE\nDГ©but: ${form.debut}${form.fin?`\nFin: ${form.fin}`:'\nDurГ©e indГ©terminГ©e avec prГ©avis raisonnable.'}\n\n`;
      doc+=`Art. 5 вҖ” CRITГҲRES D'INDГүPENDANCE (Loi 27/12/2006)\n- LibertГ© d'organisation du travail\n- LibertГ© d'organisation du temps de travail\n- PossibilitГ© de travailler pour d'autres donneurs d'ordre\n- Pas de contrГҙle hiГ©rarchique\n\n`;
      if(type==='indep_mandataire')doc+=`Art. 6 вҖ” MANDAT SOCIAL\nLe prestataire exerce un mandat de [gГ©rant/administrateur] au sein de la sociГ©tГ©.\nConformГ©ment au Code des sociГ©tГ©s et des associations (CSA).\nRГ©vocable [ad nutum / moyennant prГ©avis].\n\n`;
      if(type==='indep_conjoint_aidant')doc+=`Art. 6 вҖ” STATUT CONJOINT AIDANT\nLe prestataire aide rГ©guliГЁrement son conjoint dans l'exercice de son activitГ© indГ©pendante.\nStatut social: [maxi-statut / mini-statut].\nAffiliation caisse sociale obligatoire.\n\n`;
      doc+=`Art. ${type==='indep_mandataire'||type==='indep_conjoint_aidant'?7:6} вҖ” OBLIGATIONS SOCIALES\n`;
      doc+=`Le prestataire dГ©clare ГӘtre en rГЁgle de:\n- Affiliation Г  une caisse d'assurances sociales\n- Cotisations sociales trimestrielles\n- Assurance maladie-invaliditГ©\n- Assurance responsabilitГ© professionnelle\n\n`;
      doc+=`Fait en double exemplaire Г  ${s.co.address?.split(',').pop()?.trim()||'Bruxelles'}, le ${now}\n\n`;
      doc+=`Le donneur d'ordre:\t\t\tLe prestataire:\n[Signature]\t\t\t\t[Signature]\n`;
    }
    else if(sel.cat==='special'){
      if(type==='volontariat'){
        doc=`CONVENTION DE VOLONTARIAT\n(Loi du 03/07/2005 relative aux droits des volontaires)\nв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n\n`;
        doc+=`ENTRE:\nL'organisation: ${s.co.name}\nSiГЁge: ${s.co.address}\n\n`;
        doc+=`ET:\nLe/la volontaire: ${form.empPrenom} ${form.empNom}\n\n`;
        doc+=`Art. 1 вҖ” Le volontariat est exercГ© sans rГ©munГ©ration ni obligation.\n`;
        doc+=`Art. 2 вҖ” DГ©fraiement: forfait max 40,67вӮ¬/jour, 1.626,77вӮ¬/an (2026).\n`;
        doc+=`Art. 3 вҖ” Aucune cotisation ONSS, aucun prГ©compte professionnel.\n`;
        doc+=`Art. 4 вҖ” Assurance responsabilitГ© civile souscrite par l'organisation.\n\n`;
      }
      else if(type==='smart_sme'){
        doc=`NOTE D'INFORMATION вҖ” PORTAGE SALARIAL (Smart)\nв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n\n`;
        doc+=`Prestataire: ${form.empPrenom} ${form.empNom}\nMission: ${form.fonction}\nClient: ${s.co.name}\n\n`;
        doc+=`Smart Г©tablit le contrat de travail, facture le client, et reverse:\n- Montant facturГ© HT\n- Moins commission Smart (~6,5%)\n- Moins cotisations sociales employeur + travailleur\n- Moins prГ©compte professionnel\n= Net versГ© au prestataire\n\n`;
        doc+=`Avantages: couverture sociale complГЁte, chГҙmage, mutuelle, pension.\n`;
      }
      else{
        doc+=`Le prГ©sent contrat est de type: ${sel.l}\n${sel.desc}\n`;
        doc+=`DГ©but: ${form.debut}${form.fin?` вҖ” Fin: ${form.fin}`:''}\n`;
      }
      doc+=`\nFait Г  ${s.co.address?.split(',').pop()?.trim()||'Bruxelles'}, le ${now}\n\n`;
      doc+=`Signature 1:\t\t\t\tSignature 2:\n[Signature]\t\t\t\t[Signature]\n`;
    }
    else doc+=`DГ©but: ${form.debut}${form.fin?` вҖ” Fin: ${form.fin}`:''}\n`;
    if(sel.cat==='salarie'){
    doc+=`\nArt. 3 вҖ” LIEU DE TRAVAIL\n${form.lieuTravail}\n`;
    doc+=`\nArt. 4 вҖ” RГүMUNГүRATION\nSalaire brut mensuel: ${form.salaireBrut}вӮ¬\nMode de paiement: virement bancaire\n`;
    doc+=`\nArt. 5 вҖ” DURГүE DU TRAVAIL\nRГ©gime: ${form.regime}\nHoraire: ${form.horaire}\n`;
    doc+=`\nArt. 6 вҖ” AVANTAGES EXTRA-LГүGAUX\n${form.avantages}\n`;
    if(form.clauseNonConcurrence==='Oui')doc+=`\nArt. 7 вҖ” CLAUSE DE NON-CONCURRENCE\nConformГ©ment Г  l'art. 65 de la loi du 03/07/1978.\n`;
    if(form.clauseEcolage==='Oui')doc+=`\nArt. 8 вҖ” CLAUSE D'ГүCOLAGE\nConformГ©ment Г  l'art. 22bis de la loi du 03/07/1978.\n`;
    doc+=`\nArt. 9 вҖ” DISPOSITIONS GГүNГүRALES\nLe rГЁglement de travail fait partie intГ©grante du prГ©sent contrat.\nLe contrat est rГ©gi par la loi du 03/07/1978 relative aux contrats de travail.\n`;
    doc+=`\nFait en double exemplaire Г  ${s.co.address?.split(',').pop()?.trim()||'Bruxelles'}, le ${now}\n\n`;
    doc+=`L'employeur:\t\t\t\tLe travailleur:\n[Signature]\t\t\t\t[Signature]\n`;
    doc+=`PrГ©cГ©dГ© de la mention\t\t\tPrГ©cГ©dГ© de la mention\n"Lu et approuvГ©"\t\t\t\t"Lu et approuvГ©"\n`;
    }
    return doc;
  };
  
  return <div>
    <PH title="Contrats de travail & conventions" sub="SalariГ©s, indГ©pendants, formes spГ©ciales вҖ” 40 types de contrats belges"/>
    <div style={{display:'grid',gridTemplateColumns:'280px 1fr',gap:18}}>
      <C>
        <ST>Type de contrat</ST>
        <div style={{fontSize:10,color:'#c6a34e',fontWeight:600,marginBottom:6}}>рҹ“Ӣ SALARIГүS (Loi 03/07/1978)</div>
        {CONTRAT_TYPES.filter(ct=>ct.cat==='salarie').map(ct=><button key={ct.id} onClick={()=>setType(ct.id)} style={{display:'block',width:'100%',padding:'8px 10px',marginBottom:3,border:type===ct.id?'1px solid rgba(198,163,78,.3)':'1px solid rgba(198,163,78,.04)',borderRadius:6,background:type===ct.id?'rgba(198,163,78,.1)':'transparent',color:type===ct.id?'#c6a34e':'#9e9b93',cursor:'pointer',fontSize:11,textAlign:'left',fontFamily:'inherit',fontWeight:type===ct.id?600:400}}>
          {ct.l.split('вҖ”')[0]}
        </button>)}
        <div style={{fontSize:10,color:'#a78bfa',fontWeight:600,marginTop:12,marginBottom:6}}>рҹҸў INDГүPENDANTS (AR nВ°38)</div>
        {CONTRAT_TYPES.filter(ct=>ct.cat==='independant').map(ct=><button key={ct.id} onClick={()=>setType(ct.id)} style={{display:'block',width:'100%',padding:'8px 10px',marginBottom:3,border:type===ct.id?'1px solid rgba(167,139,250,.3)':'1px solid rgba(167,139,250,.04)',borderRadius:6,background:type===ct.id?'rgba(167,139,250,.1)':'transparent',color:type===ct.id?'#a78bfa':'#9e9b93',cursor:'pointer',fontSize:11,textAlign:'left',fontFamily:'inherit',fontWeight:type===ct.id?600:400}}>
          {ct.l.split('вҖ”')[0]}
        </button>)}
        <div style={{fontSize:10,color:'#60a5fa',fontWeight:600,marginTop:12,marginBottom:6}}>вҡЎ FORMES SPГүCIALES / HYBRIDES</div>
        {CONTRAT_TYPES.filter(ct=>ct.cat==='special').map(ct=><button key={ct.id} onClick={()=>setType(ct.id)} style={{display:'block',width:'100%',padding:'8px 10px',marginBottom:3,border:type===ct.id?'1px solid rgba(96,165,250,.3)':'1px solid rgba(96,165,250,.04)',borderRadius:6,background:type===ct.id?'rgba(96,165,250,.1)':'transparent',color:type===ct.id?'#60a5fa':'#9e9b93',cursor:'pointer',fontSize:11,textAlign:'left',fontFamily:'inherit',fontWeight:type===ct.id?600:400}}>
          {ct.l.split('вҖ”')[0]}
        </button>)}
        <div style={{marginTop:14,padding:10,background:"rgba(96,165,250,.06)",borderRadius:8,fontSize:10.5,color:'#60a5fa',lineHeight:1.5}}>
          Гүquivalent LegalSmart de Partena. Contrats gГ©nГ©rГ©s selon la loi du 03/07/1978 et les CCT applicables.
        </div>
      </C>
      <C>
        <div style={{fontSize:14,fontWeight:600,color:'#e8e6e0',marginBottom:16}}>{sel?.l}</div>
        <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12}}>
          <I label="Nom" value={form.empNom} onChange={v=>upd('empNom',v)}/>
          <I label="PrГ©nom" value={form.empPrenom} onChange={v=>upd('empPrenom',v)}/>
          <I label="NВ° National" value={form.empNN} onChange={v=>upd('empNN',v)}/>
          <I label="Adresse" value={form.empAdresse} onChange={v=>upd('empAdresse',v)}/>
          <I label="Fonction" value={form.fonction} onChange={v=>upd('fonction',v)}/>
          <I label="Salaire brut mensuel (вӮ¬)" value={form.salaireBrut} onChange={v=>upd('salaireBrut',v)}/>
          <I label="Date dГ©but" value={form.debut} onChange={v=>upd('debut',v)}/>
          {(type==='cdd'||type==='interim'||type==='etudiant')&&<I label="Date fin" value={form.fin} onChange={v=>upd('fin',v)}/>}
          <I label="RГ©gime" value={form.regime} onChange={v=>upd('regime',v)}/>
          <I label="Horaire" value={form.horaire} onChange={v=>upd('horaire',v)}/>
          <I label="Clause non-concurrence" value={form.clauseNonConcurrence} onChange={v=>upd('clauseNonConcurrence',v)} options={[{v:"Non",l:"Non"},{v:"Oui",l:"Oui"}]}/>
          <I label="Clause d'Г©colage" value={form.clauseEcolage} onChange={v=>upd('clauseEcolage',v)} options={[{v:"Non",l:"Non"},{v:"Oui",l:"Oui"}]}/>
        </div>
        <B style={{marginTop:16}} onClick={()=>{
          const doc=generate();
          d({type:"MODAL",m:{w:900,c:<div>
            <h2 style={{fontSize:17,fontWeight:600,color:'#e8e6e0',margin:'0 0 12px',fontFamily:"'Cormorant Garamond',serif"}}>{sel.l}</h2>
            <pre style={{background:"#060810",border:'1px solid rgba(139,115,60,.15)',borderRadius:8,padding:14,fontSize:10.5,color:'#9e9b93',whiteSpace:'pre-wrap',maxHeight:450,overflowY:'auto'}}>{doc}</pre>
            <div style={{display:'flex',gap:10,marginTop:14,justifyContent:'flex-end'}}>
              <B v="outline" onClick={()=>d({type:"MODAL",m:null})}>Fermer</B>
              <B onClick={()=>{navigator.clipboard?.writeText(doc);alert('CopiГ© !')}}>Copier</B>
            </div>
          </div>}});
        }}>GГ©nГ©rer le contrat</B>
      </C>
    </div>
  </div>;
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
//  COMPTE INDIVIDUEL вҖ” Annuel par travailleur
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
function CompteIndividuelMod({s,d}){
  const [yr,setYr]=useState(new Date().getFullYear());
  const ae=s.emps.filter(e=>e.status==='active');
  
  const genCI=(emp)=>{
    const p=calc(emp,DPER,s.co);
    const brut12=emp.monthlySalary*12+emp.monthlySalary; // 12 mois + 13e mois
    const onssW12=p.onssNet*13;const onssE12=p.onssE*13;
    const tax12=p.tax*13;const net12=p.net*12+emp.monthlySalary*0.6;
    const simplePec=brut12*0.0769;const doublePec=brut12*0.0769;
    return{emp:`${emp.first} ${emp.last}`,nn:emp.nn||'XX.XX.XX-XXX.XX',fn:emp.fn||'EmployГ©',
      brut12:brut12.toFixed(2),onssW:onssW12.toFixed(2),onssE:onssE12.toFixed(2),
      tax:tax12.toFixed(2),net:net12.toFixed(2),
      simplePec:simplePec.toFixed(2),doublePec:doublePec.toFixed(2),
      monthly:emp.monthlySalary,start:emp.start||'01/01/'+yr,
      regime:emp.regime||'38h/sem',statut:emp.statut||'EmployГ©',
      cp:s.co.cp||'200'};
  };
  
  const showCI=(emp)=>{
    const ci=genCI(emp);
    const doc=`COMPTE INDIVIDUEL вҖ” ANNГүE ${yr}\nв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n\n`+
    `EMPLOYEUR: ${s.co.name}\nNВ° ONSS: ${s.co.onss||'[ONSS]'}\nCP: ${ci.cp}\n\n`+
    `TRAVAILLEUR: ${ci.emp}\nNВ° National: ${ci.nn}\nFonction: ${ci.fn}\nStatut: ${ci.statut}\nRГ©gime: ${ci.regime}\nDate entrГ©e: ${ci.start}\n\n`+
    `RГүMUNГүRATIONS ${yr}\nв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n`+
    MN.map((m,i)=>`${m.padEnd(12)} Brut: ${ci.monthly.toFixed(2)}вӮ¬\tONSS: ${(ci.monthly*0.1307).toFixed(2)}вӮ¬\tPP: ${(ci.monthly*0.1307*-1+ci.monthly>2723.36?0:(2723.36-ci.monthly)*0.2307).toFixed(2)!=='NaN'?'voir fiche':'вҖ”'}\tNet: ~${(ci.monthly*0.77).toFixed(2)}вӮ¬`).join('\n')+
    `\n\n13e mois:\tBrut: ${ci.monthly.toFixed(2)}вӮ¬\n`+
    `\nTOTAUX ANNUELS\nв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n`+
    `Brut total:\t\t${ci.brut12}вӮ¬\nONSS travailleur:\t${ci.onssW}вӮ¬\nONSS employeur:\t\t${ci.onssE}вӮ¬\nPrГ©compte professionnel:\t${ci.tax}вӮ¬\n`+
    `PГ©cule simple:\t\t${ci.simplePec}вӮ¬\nPГ©cule double:\t\t${ci.doublePec}вӮ¬\n`+
    `\nCe document est Г©tabli conformГ©ment Г  l'AR du 08/08/1980.\nГҖ conserver pendant 5 ans minimum.\n`;
    
    d({type:"MODAL",m:{w:900,c:<div>
      <h2 style={{fontSize:17,fontWeight:600,color:'#e8e6e0',margin:'0 0 12px',fontFamily:"'Cormorant Garamond',serif"}}>Compte individuel {yr} вҖ” {ci.emp}</h2>
      <div style={{fontSize:11,color:'#c6a34e',marginBottom:10}}>AR 08/08/1980 вҖ” Conservation 5 ans</div>
      <pre style={{background:"#060810",border:'1px solid rgba(139,115,60,.15)',borderRadius:8,padding:14,fontSize:10,color:'#9e9b93',whiteSpace:'pre-wrap',maxHeight:450,overflowY:'auto'}}>{doc}</pre>
      <div style={{display:'flex',gap:10,marginTop:14,justifyContent:'flex-end'}}>
        <B v="outline" onClick={()=>d({type:"MODAL",m:null})}>Fermer</B>
        <B onClick={()=>{navigator.clipboard?.writeText(doc);alert('CopiГ© !')}}>Copier</B>
      </div>
    </div>}});
  };

  return <div>
    <PH title="Comptes individuels" sub={`AnnГ©e ${yr} вҖ” AR 08/08/1980`}/>
    <div style={{display:'grid',gridTemplateColumns:'260px 1fr',gap:18}}>
      <C>
        <I label="AnnГ©e" type="number" value={yr} onChange={v=>setYr(v)}/>
        <div style={{marginTop:14,padding:12,background:"rgba(198,163,78,.06)",borderRadius:8,fontSize:12,color:'#9e9b93',lineHeight:2}}>
          <div style={{fontWeight:600,color:'#c6a34e',marginBottom:4}}>RГ©sumГ©</div>
          <div>Travailleurs actifs: <b style={{color:'#e8e6e0'}}>{ae.length}</b></div>
          <div>Masse salariale: <b style={{color:'#4ade80'}}>{fmt(ae.reduce((a,e)=>a+e.monthlySalary*13,0))}</b></div>
        </div>
        <div style={{marginTop:12,padding:10,background:"rgba(96,165,250,.06)",borderRadius:8,fontSize:10.5,color:'#60a5fa',lineHeight:1.5}}>
          Le compte individuel est un document obligatoire que l'employeur doit Г©tablir pour chaque travailleur. Il reprend toutes les rГ©munГ©rations et retenues de l'annГ©e.
        </div>
      </C>
      <C style={{padding:0,overflow:'hidden'}}>
        <div style={{padding:'14px 18px',borderBottom:'1px solid rgba(139,115,60,.1)'}}><div style={{fontSize:13,fontWeight:600,color:'#e8e6e0'}}>Travailleurs вҖ” {yr}</div></div>
        <Tbl cols={[
          {k:'n',l:"Nom",b:1,r:r=>`${r.first} ${r.last}`},
          {k:'f',l:"Fonction",r:r=>r.fn||'EmployГ©'},
          {k:'s',l:"Brut mensuel",a:'right',r:r=>fmt(r.monthlySalary)},
          {k:'a',l:"Brut annuel (13m)",a:'right',r:r=><span style={{color:'#4ade80'}}>{fmt(r.monthlySalary*13)}</span>},
          {k:'x',l:"",a:'right',r:r=><B v="ghost" style={{padding:'3px 10px',fontSize:10}} onClick={()=>showCI(r)}>GГ©nГ©rer</B>}
        ]} data={ae}/>
      </C>
    </div>
  </div>;
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
//  ACCOUNTING OUTPUT вҖ” RГ©capitulatif comptable pour le comptable
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
function AccountingOutputMod({s,d}){
  const [per,setPer]=useState({m:new Date().getMonth()+1,y:new Date().getFullYear()});
  const [view,setView]=useState('onss'); // onss | fisc | partena | global
  const ae=s.emps.filter(e=>e.status==='active');
  
  const results=ae.map(emp=>{const p=calc(emp,DPER,s.co);return{...p,emp:`${emp.first} ${emp.last}`};});
  const totals={
    gross:results.reduce((a,r)=>a+r.gross,0),
    onssNet:results.reduce((a,r)=>a+r.onssNet,0),
    onssE:results.reduce((a,r)=>a+r.onssE,0),
    tax:results.reduce((a,r)=>a+r.tax,0),
    net:results.reduce((a,r)=>a+r.net,0),
    css:results.reduce((a,r)=>a+r.css,0),
    mvEmployer:results.reduce((a,r)=>a+(r.mvEmployer||0),0),
    cost:results.reduce((a,r)=>a+r.totalCost,0),
  };
  totals.onssTotal=totals.onssNet+totals.onssE;
  
  const sections={
    onss:{title:'Paiement ONSS',color:'#f87171',items:[
      {l:"ONSS travailleur (13,07%)",v:totals.onssNet,acc:'453000'},
      {l:"ONSS employeur (25%)",v:totals.onssE,acc:'453100'},
      {l:"Total ONSS Г  verser",v:totals.onssTotal,acc:'вҖ”',bold:true},
      {l:"ГүchГ©ance",v:`${per.y}-${(per.m+1).toString().padStart(2,"0")}-05`,text:true},
      {l:"Communication structurГ©e",v:`+++${s.co.onss?.replace(/[\s.-]/g,"")||'XXXXX'}/${per.y}/${per.m.toString().padStart(2,"0")}+++`,text:true},
    ]},
    fisc:{title:'Paiement PrГ©compte professionnel',color:'#fb923c',items:[
      {l:"PrГ©compte retenu",v:totals.tax,acc:'453200'},
      {l:"CSS (Cotisation spГ©ciale)",v:totals.css,acc:'453300'},
      {l:"Total PP Г  verser",v:totals.tax+totals.css,acc:'вҖ”',bold:true},
      {l:"ГүchГ©ance",v:`15/${(per.m+1).toString().padStart(2,"0")}/${per.y}`,text:true},
      {l:"Via",v:"MyMinfin (prГ©compte professionnel 274)",text:true},
    ]},
    global:{title:"Vue d'ensemble mensuelle",color:'#c6a34e',items:[
      {l:"Masse salariale brute",v:totals.gross,acc:'620000'},
      {l:"ONSS patronales",v:totals.onssE,acc:'621000'},
      {l:"ChГЁques-repas employeur",v:totals.mvEmployer,acc:'623000'},
      {l:"CoГ»t total employeur",v:totals.cost,acc:'вҖ”',bold:true},
      {l:"",v:0,sep:true},
      {l:"Net Г  payer (salaires)",v:totals.net,acc:'455000'},
      {l:"ONSS Г  payer",v:totals.onssTotal,acc:'453000/100'},
      {l:"PP Г  payer",v:totals.tax+totals.css,acc:'453200/300'},
      {l:"Total des sorties",v:totals.net+totals.onssTotal+totals.tax+totals.css+totals.mvEmployer,acc:'вҖ”',bold:true},
    ]},
  };
  const cur=sections[view];
  
  return <div>
    <PH title="Accounting Output" sub="Vue comptable des paiements ONSS, Fisc, salaires"/>
    <div style={{display:'grid',gridTemplateColumns:'260px 1fr',gap:18}}>
      <C>
        <ST>PГ©riode</ST>
        <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:9}}>
          <I label="Mois" value={per.m} onChange={v=>setPer({...per,m:parseInt(v)})} options={MN.map((m,i)=>({v:i+1,l:m}))}/>
          <I label="AnnГ©e" type="number" value={per.y} onChange={v=>setPer({...per,y:v})}/>
        </div>
        <ST>Section</ST>
        {[{v:"onss",l:"рҹ’° Paiement ONSS"},{v:"fisc",l:"рҹҸӣпёҸ PrГ©compte professionnel"},{v:"global",l:"рҹ“Ҡ Vue d\'ensemble"}].map(x=>
          <button key={x.v} onClick={()=>setView(x.v)} style={{display:'block',width:'100%',padding:'9px 12px',marginBottom:4,border:view===x.v?'1px solid rgba(198,163,78,.3)':'1px solid rgba(198,163,78,.06)',borderRadius:7,background:view===x.v?'rgba(198,163,78,.1)':'rgba(198,163,78,.02)',color:view===x.v?'#c6a34e':'#9e9b93',cursor:'pointer',fontSize:12,textAlign:'left',fontFamily:'inherit',fontWeight:view===x.v?600:400}}>{x.l}</button>
        )}
        <div style={{marginTop:14,padding:10,background:"rgba(96,165,250,.06)",borderRadius:8,fontSize:10.5,color:'#60a5fa',lineHeight:1.5}}>
          Гүquivalent du Finance Support de Partena. Export facile vers votre comptable.
        </div>
      </C>
      <C>
        <div style={{fontSize:14,fontWeight:600,color:'#e8e6e0',marginBottom:6}}>{cur.title}</div>
        <div style={{fontSize:11,color:'#5e5c56',marginBottom:16}}>{MN[per.m-1]} {per.y} вҖ” {ae.length} travailleur(s)</div>
        <div style={{display:'flex',flexDirection:'column',gap:8}}>
          {cur.items.filter(x=>!x.sep).map((it,i)=>it.text?
            <div key={i} style={{display:'flex',justifyContent:'space-between',padding:'8px 14px',background:"rgba(96,165,250,.04)",borderRadius:8}}>
              <span style={{fontSize:12,color:'#60a5fa'}}>{it.l}</span>
              <span style={{fontSize:12,color:'#e8e6e0',fontFamily:'monospace'}}>{it.v}</span>
            </div>
            :
            <div key={i} style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:'10px 14px',background:it.bold?'rgba(198,163,78,.08)':'rgba(198,163,78,.03)',borderRadius:8,border:it.bold?'1px solid rgba(198,163,78,.2)':'1px solid rgba(198,163,78,.06)'}}>
              <div>
                <span style={{fontSize:12,color:it.bold?'#c6a34e':'#d4d0c8',fontWeight:it.bold?700:400}}>{it.l}</span>
                {it.acc!=='вҖ”'&&<span style={{fontSize:10,color:'#5e5c56',marginLeft:8}}>({it.acc})</span>}
              </div>
              <span style={{fontSize:it.bold?16:13,fontWeight:it.bold?700:500,color:it.bold?cur.color:'#e8e6e0',fontFamily:'monospace'}}>{fmt(it.v)}</span>
            </div>
          )}
        </div>
        <B v="ghost" style={{width:'100%',marginTop:16,fontSize:11}} onClick={()=>{
          let csv='LibellГ©;Compte;Montant\n';
          cur.items.filter(x=>!x.sep&&!x.text).forEach(it=>{csv+=`${it.l};${it.acc};${typeof it.v==='number'?it.v.toFixed(2):it.v}\n`;});
          navigator.clipboard?.writeText(csv);alert('CSV copiГ© !');
        }}>рҹ“Ӣ Copier en CSV (pour Excel/comptable)</B>
      </C>
    </div>
  </div>;
}

