    html+=`<div class="footer"><span>Aureus IA SPRL вҖ” TVA BE 1028.230.781 вҖ” Saint-Gilles, Bruxelles</span><span>${dateStr}</span></div></body></html>`;

    // Open in new window for print/save as PDF
    const printWin=window.open('',"_blank","width=800,height=1100");
